INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('geografia', 'bachillerato', '{2}', 'Las unidades morfoestructurales del relieve peninsular', 'El relieve de la Península Ibérica se organiza en torno a una gran meseta central, rodeada y atravesada por sistemas montañosos de distinto origen geológico. El zócalo paleozoico, formado durante la orogénesis herciniana, constituye el núcleo rígido de la Meseta, fracturado y arrasado por la erosión hasta configurar penillanuras. Sobre este basamento se depositaron posteriormente materiales sedimentarios que, con la orogénesis alpina del Terciario, se plegaron y levantaron formando las cordilleras exteriores: Pirineos, Cordilleras Béticas y Costero-Catalanas. Simultáneamente, el zócalo rígido se fracturó en bloques, generando el Sistema Central y los Montes de Toledo en su interior, y reactivando los rebordes montañosos como el Macizo Galaico, la Cordillera Cantábrica, el Sistema Ibérico y Sierra Morena. Entre estas unidades aparecen las depresiones exteriores del Ebro y el Guadalquivir, fosas rellenas de sedimentos terciarios y cuaternarios. La disposición periférica de las montañas y la elevada altitud media, superior a los 660 metros, explican el aislamiento del interior, la continentalización del clima y la disposición radial de los ríos. Esta compleja arquitectura es resultado de más de quinientos millones de años de historia geológica, en los que se suceden fases de sedimentación, plegamiento, fractura y erosión diferencial. El conocimiento de estas unidades morfoestructurales resulta imprescindible para comprender la diversidad paisajística española y la distribución de los recursos naturales, las vías de comunicación y los asentamientos humanos a lo largo del territorio peninsular.',
'[{"pregunta":"¿Qué orogénesis originó el zócalo paleozoico de la Meseta?","opciones":["Alpina","Herciniana","Caledoniana","Cadomiense"],"correcta":1},{"pregunta":"¿Qué efecto tuvo la orogénesis alpina sobre el zócalo rígido interior?","opciones":["Lo plegó completamente","Lo fracturó en bloques","Lo hundió bajo el mar","No lo afectó en absoluto"],"correcta":1},{"pregunta":"¿Qué consecuencia climática se deriva de la disposición periférica de las montañas?","opciones":["Clima oceánico generalizado","Continentalización del interior","Aridez costera","Tropicalización del sur"],"correcta":1},{"pregunta":"¿Qué son las depresiones del Ebro y del Guadalquivir según el texto?","opciones":["Macizos paleozoicos","Fosas rellenas de sedimentos terciarios","Cuencas volcánicas","Plataformas marinas emergidas"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'La diversidad climática de España', 'España presenta una notable diversidad climática derivada de su posición en la zona templada, su carácter peninsular entre dos masas de agua contrastadas, el Atlántico y el Mediterráneo, y la compleja disposición del relieve. El dominio oceánico, característico de la franja cantábrica y de Galicia, se define por temperaturas suaves, escasa amplitud térmica y precipitaciones abundantes y regulares a lo largo del año, superiores a los 800 mm anuales. El dominio mediterráneo, presente en la mayor parte del territorio, se caracteriza por veranos calurosos y secos e inviernos suaves, con precipitaciones concentradas en primavera y otoño y un marcado déficit hídrico estival. Dentro de este dominio se distinguen variantes: el mediterráneo típico costero, el continentalizado del interior peninsular con mayor amplitud térmica, y el seco o estepario del sureste, donde las precipitaciones no alcanzan los 300 mm anuales. A estos dominios se suman el clima de montaña, por encima de los 1.000 metros, con temperaturas frías y precipitaciones abundantes muchas veces en forma de nieve, y el subtropical canario, suavizado por la corriente fría de Canarias y los vientos alisios. Esta diversidad explica la variedad de formaciones vegetales, desde el bosque caducifolio atlántico hasta las formaciones xerófilas del sureste, y condiciona los usos agrícolas, la distribución de la población, el turismo y la demanda energética. Comprender los factores geográficos y termodinámicos que determinan cada dominio constituye una herramienta esencial para interpretar los paisajes y los retos ambientales del país.',
'[{"pregunta":"¿Qué dominio climático presenta precipitaciones superiores a 800 mm regulares todo el año?","opciones":["Mediterráneo típico","Oceánico","Estepario","Subtropical canario"],"correcta":1},{"pregunta":"¿Qué rasgo define al dominio mediterráneo?","opciones":["Inviernos extremadamente fríos","Veranos calurosos y secos con déficit hídrico","Precipitaciones uniformes todo el año","Ausencia de estaciones marcadas"],"correcta":1},{"pregunta":"¿Dónde se localiza la variante estepária del clima mediterráneo?","opciones":["Galicia","Sureste peninsular","Pirineos","Costa cantábrica"],"correcta":1},{"pregunta":"¿Qué factor suaviza el clima subtropical canario?","opciones":["La corriente cálida del Golfo","La corriente fría de Canarias y los alisios","La altitud media elevada","Los vientos monzónicos"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'La red hidrográfica española y sus cuencas', 'La red hidrográfica española se organiza a partir de la disposición del relieve, la distribución de las precipitaciones y la historia geológica del territorio. La vertiente cantábrica agrupa ríos cortos, caudalosos y de régimen regular, alimentados por precipitaciones abundantes y constantes a lo largo del año, lo que los convierte en recursos valiosos para la producción hidroeléctrica. La vertiente atlántica, mucho más extensa, recoge la escorrentía de la mayor parte de la Meseta y del oeste peninsular a través de grandes colectores como el Duero, el Tajo, el Guadiana y el Guadalquivir, ríos de trazado longitudinal, mayor longitud y caudales con fuerte irregularidad estacional y anual. La vertiente mediterránea concentra cursos cortos, de régimen pluvial muy irregular, entre los que destacan el Ebro, el mayor caudal del país, y ríos como el Júcar, el Turia o el Segura, sometidos a un acusado estiaje y a episodios catastróficos de crecidas. La escasez estructural de agua en el este y sureste, agravada por el cambio climático, ha motivado una compleja política hidráulica basada en la construcción de embalses, trasvases entre cuencas y la desalación. Los planes hidrológicos actuales priorizan la gestión integrada del recurso, la recuperación del buen estado ecológico de las masas de agua exigido por la Directiva Marco y la adaptación al estrés hídrico creciente. La hidrografía española refleja, así, un equilibrio precario entre demanda agrícola, urbana, energética y ambiental.',
'[{"pregunta":"¿Por qué la vertiente cantábrica tiene régimen regular?","opciones":["Porque nace en la Meseta","Por precipitaciones abundantes y constantes","Por sus grandes embalses","Porque depende del deshielo alpino"],"correcta":1},{"pregunta":"¿Qué río tiene mayor caudal de España?","opciones":["Tajo","Ebro","Duero","Guadalquivir"],"correcta":1},{"pregunta":"¿Qué caracteriza a los ríos mediterráneos?","opciones":["Régimen nival estable","Régimen pluvial muy irregular con estiaje","Caudales uniformes todo el año","Fuentes glaciares permanentes"],"correcta":1},{"pregunta":"¿Qué exige la Directiva Marco del Agua?","opciones":["Aumentar los trasvases","Recuperar el buen estado ecológico","Privatizar las cuencas","Eliminar los embalses"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Retos demográficos de la España actual', 'La población española afronta en la actualidad un conjunto de transformaciones estructurales que configuran un escenario demográfico complejo. La transición demográfica concluida a finales del siglo XX dio paso a un régimen de baja natalidad y baja mortalidad, con una esperanza de vida entre las más altas del mundo, superior a los 83 años. La tasa de fecundidad, situada en torno a 1,2 hijos por mujer, se halla muy por debajo del nivel de reemplazo generacional, lo que provoca un acusado envejecimiento de la pirámide y la inversión progresiva entre cohortes jóvenes y mayores. Este envejecimiento tensiona el sistema de pensiones, la sanidad y los servicios de atención a la dependencia, al tiempo que reduce la fuerza laboral disponible. El crecimiento vegetativo negativo se compensa parcialmente con los saldos migratorios exteriores positivos, procedentes principalmente de América Latina, el Magreb y Europa del Este, mientras que el interior del país sigue marcado por un éxodo rural que ha vaciado amplias zonas del centro peninsular, fenómeno conocido como "la España vaciada". La distribución territorial presenta fuertes contrastes entre un litoral densamente poblado y un interior con densidades bajísimas. Las políticas públicas recientes apuntan a la conciliación laboral y familiar, al reto demográfico del medio rural, a la integración de población inmigrante y al fomento de la natalidad, aunque los resultados son limitados. Comprender estos procesos resulta clave para planificar el futuro del estado del bienestar y la cohesión territorial.',
'[{"pregunta":"¿Cuál es aproximadamente la tasa de fecundidad española según el texto?","opciones":["2,1","1,2","0,5","3,0"],"correcta":1},{"pregunta":"¿Qué es la España vaciada?","opciones":["Zonas litorales despobladas","Áreas del interior peninsular con éxodo rural","Zonas sin agua potable","Regiones sin servicios sanitarios"],"correcta":1},{"pregunta":"¿Qué compensa el crecimiento vegetativo negativo?","opciones":["El aumento de la natalidad","Los saldos migratorios exteriores","El retorno de jubilados","La inmigración interior"],"correcta":1},{"pregunta":"¿Qué sistema se ve tensionado por el envejecimiento?","opciones":["El sistema educativo","El sistema de pensiones y dependencia","El sistema bancario","El mercado inmobiliario"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'El sistema urbano español', 'El sistema urbano español se caracteriza por una organización jerárquica y desigual, fruto de procesos históricos de larga duración y de la intensa urbanización del siglo XX. En su cúspide se sitúan Madrid y Barcelona como metrópolis globales, centros de decisión económica, financiera y cultural, seguidas por metrópolis regionales como Valencia, Sevilla, Bilbao, Málaga o Zaragoza, que articulan amplios espacios funcionales. El tejido urbano se completa con ciudades medias que actúan como cabeceras comarcales y pequeñas ciudades vinculadas a ejes dinámicos. El proceso de urbanización, acelerado desde los años sesenta, se produjo mediante el éxodo rural masivo, la concentración industrial en torno a determinadas áreas y, más recientemente, la suburbanización, que ha desplazado a la población hacia coronas metropolitanas y municipios periféricos. Esta dinámica ha generado fenómenos como la expansión urbana difusa, la segregación socioespacial, la saturación del transporte, la presión inmobiliaria y la fragmentación paisajística. Las ciudades españolas presentan además un plano heredado muy diverso, con cascos históricos de origen romano, medieval o colonial, ensanches decimonónicos de inspiración higienista y polígonos residenciales del desarrollismo. Los retos actuales incluyen la rehabilitación del parque construido, la movilidad sostenible, la mitigación del efecto isla de calor y la adaptación al cambio climático. La planificación urbana debe conciliar el derecho a la vivienda, la cohesión social, el patrimonio y la eficiencia ecológica, con especial atención a las áreas metropolitanas y al reto del policentrismo territorial.',
'[{"pregunta":"¿Qué ciudades ocupan la cúspide del sistema urbano español?","opciones":["Valencia y Sevilla","Madrid y Barcelona","Bilbao y Zaragoza","Málaga y Palma"],"correcta":1},{"pregunta":"¿Qué proceso ha desplazado población a las coronas metropolitanas?","opciones":["Éxodo rural","Suburbanización","Gentrificación","Ruralización"],"correcta":1},{"pregunta":"¿Cómo se describe el plano heredado de las ciudades?","opciones":["Uniforme y moderno","Muy diverso: romano, medieval, ensanches, polígonos","Exclusivamente medieval","Puramente colonial"],"correcta":1},{"pregunta":"¿Qué reto urbano actual menciona el texto?","opciones":["Aumentar polígonos industriales","Mitigar la isla de calor y movilidad sostenible","Construir nuevas murallas","Eliminar espacios verdes"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Transformaciones del espacio rural español', 'El espacio rural español ha experimentado profundas transformaciones desde mediados del siglo XX, pasando de una sociedad agraria tradicional a un medio rural diversificado e integrado en las dinámicas globales. La modernización agraria, impulsada por la mecanización, el uso de fertilizantes, la concentración parcelaria y la entrada en la Política Agraria Común europea en 1986, ha elevado la productividad pero también ha generado desequilibrios: abandono de las zonas marginales, intensificación insostenible en áreas fértiles y dependencia de subvenciones. El sector agrario representa hoy una proporción mínima del empleo y del PIB, pero continúa vertebrando el territorio y asegurando la soberanía alimentaria. Paralelamente, el medio rural ha asumido funciones nuevas: turismo rural, conservación ambiental, producción energética renovable, acogida de actividades residenciales y neorruralismo. La agricultura ecológica y las denominaciones de origen protegidas han revalorizado producciones locales y singularizado territorios. Sin embargo, persisten graves retos: despoblación severa en extensas comarcas del interior, envejecimiento, escasa relevo generacional, déficits en servicios básicos y conectividad digital insuficiente. La Estrategia frente al Reto Demográfico y los fondos europeos de recuperación se orientan a invertir esta dinámica mediante inversiones en infraestructuras, vivienda, digitalización y empleo. La multifuncionalidad del medio rural y su papel en la transición ecológica reclaman un nuevo pacto territorial capaz de conciliar producción, sostenibilidad y equidad con el medio urbano.',
'[{"pregunta":"¿En qué año entró España en la Política Agraria Común europea?","opciones":["1975","1986","1992","2000"],"correcta":1},{"pregunta":"¿Qué funciones nuevas ha asumido el medio rural?","opciones":["Solo cultivos intensivos","Turismo, conservación, renovables, neorruralismo","Exclusivamente ganadería","Minería y canteras"],"correcta":1},{"pregunta":"¿Cuál es un reto persistente del medio rural?","opciones":["Exceso de población joven","Despoblación y envejecimiento","Saturación turística generalizada","Urbanización masiva"],"correcta":1},{"pregunta":"¿Qué valorizan las denominaciones de origen protegidas?","opciones":["Productos industriales","Producciones locales singularizadas","Monocultivos extensivos","Importaciones extranjeras"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Los sectores industriales y la terciarización', 'La economía española ha experimentado desde los años setenta una acelerada terciarización que ha reducido el peso del sector industrial y ha convertido a los servicios en la rama más dinámica y creadora de empleo. La industria española, tras los planes de desarrollo del franquismo y la reconversión industrial de los años ochenta, concentra sus actividades en sectores maduros como la alimentación, el automóvil, la química, la metalurgia y los materiales de construcción, junto a ramas tecnológicamente avanzadas como la aeronáutica, la biotecnología, las energías renovables y las TIC. La distribución territorial muestra una fuerte concentración en torno a ejes como el Mediterráneo, el valle del Ebro, el País Vasco, Madrid y algunas áreas litorales, frente a extensas zonas con escasa implantación industrial. La globalización y la deslocalización han presionado a la baja a industrias intensivas en mano de obra, mientras emergen nuevos clústeres de innovación vinculados a centros tecnológicos y universidades. El sector servicios, por su parte, agrupa ramas muy heterogéneas: turismo, comercio, transporte, finanzas, servicios a empresas, educación, sanidad y administración pública. El turismo, con más de 80 millones de visitantes anuales antes de la pandemia, es un pilar estratégico, aunque vulnerable a la estacionalidad, a la saturación de determinados destinos y al cambio climático. Los retos actuales pasan por reindustrializar de forma selectiva, impulsar la economía del conocimiento, digitalizar los servicios tradicionales y avanzar hacia un modelo productivo más resiliente, sostenible y equilibrado territorialmente.',
'[{"pregunta":"¿Qué proceso ha reducido el peso industrial en favor de los servicios?","opciones":["Industrialización","Terciarización","Colectivización","Reagrarización"],"correcta":1},{"pregunta":"¿Qué sectores industriales avanzados menciona el texto?","opciones":["Textil y minería","Aeronáutica, biotecnología, renovables","Calzado y conservas","Siderurgia pesada"],"correcta":1},{"pregunta":"¿Cuál es un punto vulnerable del turismo español?","opciones":["Falta total de visitantes","Estacionalidad y saturación","Nivel de precios mínimo","Ausencia de infraestructuras"],"correcta":1},{"pregunta":"¿Qué reto productivo señala el texto?","opciones":["Desindustrialización completa","Reindustrialización selectiva y economía del conocimiento","Regreso a la agricultura tradicional","Eliminación de los servicios"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'La organización territorial del Estado autonómico', 'La Constitución de 1978 instauró en España un modelo de organización territorial basado en la autonomía política de nacionalidades y regiones, dando lugar al Estado de las Autonomías, una de las formas de descentralización más avanzadas de Europa. El proceso autonómico se desarrolló mediante dos vías: la del artículo 151, reservada inicialmente a Cataluña, País Vasco, Galicia y posteriormente Andalucía, que permitía acceder rápidamente al máximo techo competencial; y la del artículo 143, seguida por el resto de territorios, con un acceso más gradual. Los Estatutos de Autonomía definen las instituciones propias y las competencias exclusivas, compartidas o concurrentes. Las reformas posteriores, especialmente entre 2006 y 2010, ampliaron el autogobierno en aspectos como la financiación, la justicia y el reconocimiento identitario, aunque algunas provocaron tensiones constitucionales. La financiación autonómica descansa sobre un sistema común y un régimen foral específico para el País Vasco y Navarra, lo que genera desigualdades debatidas por los diversos territorios. El modelo ha consolidado servicios públicos de proximidad en educación, sanidad o dependencia, acercando la gestión a la ciudadanía. Sin embargo, persisten desequilibrios económicos entre comunidades, debates sobre solidaridad interterritorial y demandas de mayor autogobierno e incluso de autodeterminación. La cohesión territorial constituye uno de los grandes retos del sistema autonómico, que debe combinar unidad, diversidad, suficiencia financiera y eficacia administrativa para responder a las necesidades de una sociedad compleja y plural.',
'[{"pregunta":"¿Qué Constitución instauró el Estado de las Autonomías?","opciones":["La de 1812","La de 1931","La de 1978","La de 1869"],"correcta":2},{"pregunta":"¿Qué vía autonómica permitía acceso rápido al máximo techo competencial?","opciones":["Artículo 143","Artículo 151","Artículo 155","Artículo 2"],"correcta":1},{"pregunta":"¿Qué territorios tienen régimen foral específico?","opciones":["Cataluña y Galicia","País Vasco y Navarra","Andalucía y Murcia","Madrid y Valencia"],"correcta":1},{"pregunta":"¿Qué reto destaca el texto sobre el modelo autonómico?","opciones":["La centralización total","La cohesión territorial y solidaridad","La supresión de competencias","El retorno provincial"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Medio ambiente y problemas ecológicos', 'España afronta un conjunto de problemas medioambientales derivados del cambio climático global, de la presión antrópica y de un modelo económico todavía insuficientemente sostenible. La erosión del suelo, especialmente grave en el sureste peninsular y Canarias, resulta de la deforestación histórica, los incendios, las prácticas agrícolas intensivas y la torrencialidad del clima mediterráneo, amenazando con procesos de desertificación que afectan a más de un tercio del territorio. La escasez hídrica se agudiza por el descenso de las precipitaciones, el aumento de las temperaturas medias y la sobreexplotación de acuíferos, afectando a la agricultura, al abastecimiento urbano y a los ecosistemas fluviales. La contaminación atmosférica en áreas metropolitanas, originada principalmente por el tráfico rodado, la industria y la calefacción, genera episodios de mala calidad del aire con efectos sobre la salud pública. La pérdida de biodiversidad está vinculada a la destrucción de hábitats, las especies invasoras y la fragmentación del territorio. Los incendios forestales, agravados por el abandono rural, la acumulación de biomasa y las olas de calor, se intensifican cada verano. Frente a estos desafíos, las políticas públicas se articulan en torno a la Estrategia Española de Desarrollo Sostenible, la transición energética, la Red Natura 2000, la Ley de Cambio Climático y los compromisos del Pacto Verde Europeo. La participación ciudadana, la educación ambiental y la innovación tecnológica son herramientas imprescindibles para avanzar hacia la sostenibilidad territorial y ecológica.',
'[{"pregunta":"¿Qué porcentaje aproximado del territorio afecta la desertificación?","opciones":["Menos del 5%","Alrededor de un tercio","Un 80%","Casi nada"],"correcta":1},{"pregunta":"¿Cuál es una causa de la contaminación atmosférica urbana?","opciones":["La agricultura ecológica","El tráfico rodado e industria","La ganadería extensiva","El turismo rural"],"correcta":1},{"pregunta":"¿Qué factor agrava los incendios forestales?","opciones":["La repoblación agraria","El abandono rural y olas de calor","La humedad constante","La ausencia de biomasa"],"correcta":1},{"pregunta":"¿Qué red europea de espacios protegidos menciona el texto?","opciones":["Red ERASMUS","Red Natura 2000","Red Schengen","Red Galileo"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'España en la Unión Europea y el mundo', 'La integración de España en las Comunidades Europeas en 1986 supuso un cambio estructural en su posición geopolítica, económica y territorial. El acceso al mercado único, a los fondos estructurales y de cohesión, y a las políticas comunes transformó las infraestructuras, modernizó sectores productivos y consolidó la democracia tras la Transición. España se convirtió en un actor relevante en la construcción europea, impulsando políticas como la Unión Económica y Monetaria, la Política Exterior y de Seguridad Común y la Agenda Mediterránea. La adopción del euro en 2002 profundizó la integración financiera, aunque también expuso al país a la volatilidad de los mercados durante la crisis de 2008. En el plano territorial, los fondos europeos financiaron la red de alta velocidad ferroviaria, carreteras, aeropuertos, depuradoras y equipamientos, reduciendo diferencias con los países más desarrollados. En el contexto global, España participa en organismos como la ONU, la OTAN, la OCDE y el G20, y mantiene vínculos preferentes con Iberoamérica y el Magreb. Su economía presenta una alta apertura exterior, con exportaciones crecientes de bienes industriales y agroalimentarios, aunque persiste un déficit comercial estructural. Los retos actuales incluyen el papel en la transición digital y verde europea, la respuesta a la migración, la autonomía estratégica frente a tensiones geopolíticas y el refuerzo del multilateralismo. España, por su ubicación entre Europa, el Mediterráneo, el Atlántico e Iberoamérica, posee una posición geoestratégica singular que continúa definiendo su proyección internacional.',
'[{"pregunta":"¿En qué año se adoptó el euro en España?","opciones":["1986","1999","2002","2010"],"correcta":2},{"pregunta":"¿Qué infraestructuras fueron financiadas con fondos europeos según el texto?","opciones":["Solo carreteras","Alta velocidad, carreteras, aeropuertos y depuradoras","Solo centrales nucleares","Exclusivamente puertos"],"correcta":1},{"pregunta":"¿Con qué regiones mantiene España vínculos preferentes?","opciones":["Asia y Oceanía","Iberoamérica y Magreb","Ártico y Antártida","África subsahariana exclusivamente"],"correcta":1},{"pregunta":"¿Qué rasgo estructural presenta el comercio exterior?","opciones":["Superávit comercial permanente","Déficit comercial estructural","Equilibrio total","Ausencia de exportaciones"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'El turismo como pilar económico y territorial', 'El turismo constituye uno de los pilares fundamentales de la economía española, representando en torno al 12% del PIB y generando más de 2,5 millones de empleos directos e indirectos antes de la pandemia. España es la segunda potencia turística mundial por número de visitantes internacionales, beneficiándose de un clima favorable, una costa privilegiada, un rico patrimonio histórico-artístico y una infraestructura consolidada. El modelo tradicional de "sol y playa", concentrado en el Mediterráneo y las islas, sigue siendo dominante, pero coexiste con modalidades emergentes como el turismo cultural, urbano, rural, deportivo, enogastronómico, de congresos y de naturaleza. La estacionalidad sigue siendo un problema estructural, con picos estivales que saturan destinos y capacidades, y una fuerte dependencia de mercados emisores europeos como Reino Unido, Alemania y Francia. El turismo genera importantes impactos territoriales: dinamización económica, pero también presión urbanística, especulación inmobiliaria, consumo de suelo y de agua, contaminación costera y gentrificación en centros históricos. La pandemia de COVID-19 paralizó temporalmente la actividad, evidenciando la vulnerabilidad del sector y la necesidad de diversificar. Las estrategias actuales promueven un turismo más sostenible, de calidad, desestacionalizado y distribuido territorialmente, apoyado en la digitalización, la innovación y el patrimonio. La tensión entre rentabilidad económica y capacidad de carga de los destinos constituye uno de los grandes desafíos, especialmente en ciudades patrimonio y espacios naturales protegidos, donde el fenómeno de la turistificación exige medidas de regulación y planificación.',
'[{"pregunta":"¿Qué porcentaje del PIB representa aproximadamente el turismo?","opciones":["Alrededor del 2%","En torno al 12%","Un 40%","Menos del 1%"],"correcta":1},{"pregunta":"¿Cuál es el modelo turístico tradicional dominante?","opciones":["Turismo de congresos","Sol y playa","Turismo científico","Ecoturismo exclusivo"],"correcta":1},{"pregunta":"¿Qué problema estructural persiste en el turismo español?","opciones":["La falta de patrimonio","La estacionalidad","La ausencia de hoteles","El frío generalizado"],"correcta":1},{"pregunta":"¿Qué es la turistificación?","opciones":["Reducción del turismo","Saturación turística que exige regulación","Fomento del turismo rural","Un tipo de transporte"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Los paisajes agrarios españoles', 'Los paisajes agrarios españoles son el resultado de la interacción secular entre los factores físicos del medio y la acción humana sobre el territorio. En el norte peninsular, el paisaje atlántico-húmedo se caracteriza por un minifundio heredado del sistema de herencia igualitaria, con parcelas pequeñas y cerradas por setos o bocage, dedicadas a la ganadería bovina intensiva, los prados permanentes y pequeños cultivos de huerta y maíz. El paisaje mediterráneo presenta dos variantes principales: el de secano, dominado por la trilogía mediterránea de trigo, vid y olivo, con parcelas abiertas en openfield, y el de regadío, que aprovecha vegas y huertas históricas como las del Levante, el Ebro o el Guadalquivir para producciones intensivas hortofrutícolas destinadas a la exportación. El paisaje de interior, heredero del latifundio castellano y andaluz, se asocia a grandes explotaciones cerealistas, olivareras o de dehesa, con baja densidad poblacional y mecanización avanzada. En las zonas de montaña persisten sistemas agrosilvopastoriles de economía mixta, muy afectados por el abandono rural. En Canarias, los paisajes agrarios combinan cultivos tropicales como el plátano y el tomate en áreas costeras con agricultura de subsistencia en medianías. Estos paisajes no solo son espacios productivos, sino también patrimonio cultural, refugio de biodiversidad y elemento esencial de la identidad territorial. Su conservación exige políticas que equilibren la viabilidad económica, la sostenibilidad ambiental y el reconocimiento del valor paisajístico ante las presiones de la intensificación y el abandono.',
'[{"pregunta":"¿Qué caracteriza al paisaje atlántico-húmedo del norte?","opciones":["Grandes latifundios abiertos","Minifundio con parcelas cerradas","Monocultivo del olivo","Cultivo intensivo de arroz"],"correcta":1},{"pregunta":"¿Qué trilogía caracteriza el secano mediterráneo?","opciones":["Maíz, patata, remolacha","Trigo, vid y olivo","Arroz, té, algodón","Cebada, centeno, avena"],"correcta":1},{"pregunta":"¿A qué paisaje se asocia el latifundio?","opciones":["Norte atlántico","Interior castellano y andaluz","Costa cantábrica","Islas Baleares"],"correcta":1},{"pregunta":"¿Qué valor añadido tienen los paisajes agrarios según el texto?","opciones":["Son puramente decorativos","Son patrimonio cultural y refugio de biodiversidad","Son solo productivos","Son exclusivamente turísticos"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Las fuentes de energía y la transición energética', 'España ha avanzado significativamente en la diversificación de su mix energético, aunque continúa dependiendo de combustibles fósiles importados, lo que compromete su soberanía y sostenibilidad. La dependencia energética exterior supera el 70%, una de las más altas de la Unión Europea, debido a la escasez de recursos propios de petróleo, gas y carbón. Sin embargo, el país dispone de un enorme potencial en energías renovables, gracias a su elevada radiación solar, a sus extensas zonas ventosas y a sus cuencas hidrográficas. La energía eólica ha experimentado un crecimiento espectacular y sitúa a España entre los primeros productores mundiales, mientras la solar fotovoltaica y termosolar se expanden rápidamente gracias a la caída de costes y a las subastas públicas. La hidroelectricidad, consolidada desde el siglo XX, sigue aportando un porcentaje relevante, aunque condicionado por la variabilidad pluviométrica. Las centrales nucleares, en proceso de cierre gradual, aportan todavía una parte importante de la generación eléctrica. La transición energética responde al Plan Nacional Integrado de Energía y Clima (PNIEC) y al Pacto Verde Europeo, con objetivos ambiciosos de descarbonización, eficiencia energética, autoconsumo, movilidad eléctrica e hidrógeno verde. Los retos incluyen la reforma del sistema eléctrico, la integración de renovables intermitentes mediante almacenamiento y redes inteligentes, el impacto territorial y paisajístico de las nuevas instalaciones y la transición justa para las comarcas afectadas por cierres de minería y térmicas. El éxito de la transición determinará la competitividad y la sostenibilidad del modelo económico español.',
'[{"pregunta":"¿Qué porcentaje supera la dependencia energética exterior?","opciones":["20%","70%","10%","5%"],"correcta":1},{"pregunta":"¿En qué energía renovable está España entre los primeros productores mundiales?","opciones":["Geotérmica","Eólica","Mareomotriz","Biomasa forestal"],"correcta":1},{"pregunta":"¿Qué plan articula la transición energética en España?","opciones":["PNIEC","PAC","POUM","PGOU"],"correcta":0},{"pregunta":"¿Qué reto territorial plantea la transición?","opciones":["El impacto paisajístico de nuevas instalaciones","La falta total de sol","El exceso de carbón nacional","La prohibición del autoconsumo"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'El transporte y las comunicaciones', 'La red de transporte y comunicaciones de España se ha transformado radicalmente desde los años ochenta, convirtiéndose en una de las más modernas de Europa gracias a la inversión pública, a los fondos europeos y a la liberalización del sector. La red viaria se extiende por más de 165.000 kilómetros, con una estructura radial centrada históricamente en Madrid, complementada por ejes transversales en desarrollo. La red ferroviaria ha experimentado un cambio sin precedentes con el despliegue del AVE, situando al país como segunda potencia mundial en alta velocidad, con más de 3.500 km operativos que conectan las principales ciudades. Los puertos constituyen una pieza clave en la logística internacional, dado el carácter marítimo del comercio exterior; destacan Algeciras, Valencia, Barcelona y Bilbao entre los mayores del Mediterráneo. La red aeroportuaria, liderada por Madrid-Barajas y Barcelona-El Prat, gestiona un elevado volumen de pasajeros vinculado al turismo, las conexiones intraeuropeas y las rutas intercontinentales. Las telecomunicaciones han evolucionado rápidamente con la fibra óptica, el 5G y la digitalización administrativa, aunque persisten brechas digitales en zonas rurales. Los retos del sistema incluyen la descarbonización del transporte, la promoción del ferrocarril de mercancías, la intermodalidad, la reducción de emisiones y la cohesión territorial de áreas escasamente conectadas. Las inversiones del Mecanismo de Recuperación y Resiliencia europeo se orientan a estos objetivos, buscando un sistema de movilidad más eficiente, sostenible e integrado.',
'[{"pregunta":"¿Qué posición ocupa España en alta velocidad ferroviaria mundial?","opciones":["Primera","Segunda","Quinta","Décima"],"correcta":1},{"pregunta":"¿Qué puerto del Mediterráneo destaca el texto?","opciones":["Santander","Algeciras","Gijón","Vigo"],"correcta":1},{"pregunta":"¿Qué característica histórica tiene la red viaria?","opciones":["Estructura radial centrada en Madrid","Estructura exclusivamente costera","Ausencia de autopistas","Red totalmente transversal"],"correcta":0},{"pregunta":"¿Qué persiste en zonas rurales sobre telecomunicaciones?","opciones":["Saturación 5G","Brechas digitales","Exceso de fibra óptica","Ausencia total"],"correcta":1}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Los desequilibrios territoriales en España', 'España presenta importantes desequilibrios territoriales fruto de factores geográficos, históricos y económicos acumulados a lo largo de siglos. La concentración de la población, la actividad económica y los servicios en el litoral mediterráneo, el eje del Ebro, el área madrileña y las islas contrasta con el vaciamiento del interior peninsular, donde extensas comarcas registran densidades inferiores a 10 habitantes por kilómetro cuadrado. Las diferencias en renta per cápita entre comunidades como Madrid, País Vasco o Navarra y otras como Extremadura, Andalucía o Castilla-La Mancha alcanzan proporciones considerables, reflejando desigualdades en productividad, capital humano, infraestructuras y especialización económica. Los desequilibrios se manifiestan también en el acceso a servicios públicos, en la conectividad digital, en las oportunidades laborales y en la dinámica demográfica. Factores históricos como la concentración del poder político en la capital, la localización costera de las redes industriales del siglo XIX, la desigual intensidad del desarrollismo franquista o la entrada selectiva de inversiones europeas han consolidado este modelo desigual. Las políticas de cohesión territorial, articuladas a través de fondos europeos, la planificación estatal y las competencias autonómicas, han intentado corregir estas diferencias, pero los resultados son limitados. El reto demográfico, la digitalización, la transición ecológica y la reforma de la financiación autonómica abren hoy nuevas oportunidades para reequilibrar el territorio. La cohesión territorial exige un modelo policéntrico, cooperativo entre administraciones, capaz de garantizar igualdad de oportunidades en todo el Estado y de conciliar competitividad con justicia espacial.',
'[{"pregunta":"¿Qué densidad registra extensas comarcas del interior?","opciones":["Inferior a 10 hab/km²","Más de 1000 hab/km²","Entre 100 y 200 hab/km²","Exactamente 50 hab/km²"],"correcta":0},{"pregunta":"¿Qué comunidades tienen mayor renta per cápita según el texto?","opciones":["Extremadura y Andalucía","Madrid, País Vasco y Navarra","Galicia y Canarias","Murcia y La Rioja"],"correcta":1},{"pregunta":"¿Qué factor histórico consolidó desigualdades?","opciones":["La distribución uniforme del poder","La localización costera de la industria del XIX","La ausencia de fondos europeos","La planificación socialista centralizada"],"correcta":1},{"pregunta":"¿Qué modelo se propone para reequilibrar el territorio?","opciones":["Centralismo radical","Modelo policéntrico cooperativo","Exclusiva autonomía local","Supresión autonómica"],"correcta":1}]'::jsonb);

