INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('economia-empresa', 'bachillerato', '{2}', 'Formas jurídicas de la empresa', 'La elección de la forma jurídica es una de las decisiones más trascendentales en la creación de una empresa, ya que condiciona la responsabilidad de los socios, la fiscalidad aplicable, los requisitos legales, la capacidad de financiación y los órganos de gobierno. El empresario individual o autónomo responde con todo su patrimonio personal de las deudas contraídas, lo que entraña un alto riesgo pese a la sencillez de su constitución. Las sociedades mercantiles, en cambio, ofrecen formas más protegidas. La Sociedad de Responsabilidad Limitada (SL) es la más extendida entre las pymes, exige un capital mínimo de 3.000 euros dividido en participaciones no libremente transmisibles y limita la responsabilidad de los socios al capital aportado. La Sociedad Anónima (SA) requiere 60.000 euros de capital mínimo y divide éste en acciones, lo que facilita la captación de recursos en mercados organizados y la entrada en bolsa, siendo típica de grandes empresas. Las cooperativas se rigen por principios democráticos: un socio, un voto, con finalidad de prestar servicios a sus miembros más que maximizar beneficios. Existen además formas específicas como la sociedad laboral, cuyo capital pertenece mayoritariamente a los trabajadores. La fiscalidad varía: el autónomo tributa por IRPF, mientras sociedades mercantiles tributan por Impuesto sobre Sociedades. La decisión debe sopesar factores como el tamaño previsto, el número de socios, el riesgo asumible, las necesidades de capital y la estrategia de crecimiento, asesorándose adecuadamente para evitar errores costosos en etapas posteriores del proyecto empresarial.',
'[{"pregunta":"¿Con qué responde el empresario individual?","opciones":["Solo con el capital social","Con todo su patrimonio personal","Con un fondo mutualista","Con nada"],"correcta":1},{"pregunta":"¿Cuál es el capital mínimo de una SA?","opciones":["3.000 euros","60.000 euros","1 euro","100.000 euros"],"correcta":1},{"pregunta":"¿Qué principio rige las cooperativas?","opciones":["Una acción, un voto","Un socio, un voto","Voto proporcional al capital","Voto único del presidente"],"correcta":1},{"pregunta":"¿Qué impuesto grava a las sociedades mercantiles?","opciones":["IRPF","Impuesto sobre Sociedades","IVA exclusivamente","Impuesto de Patrimonio"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El balance de situación', 'El balance de situación es el documento contable que ofrece una imagen fiel del patrimonio de la empresa en un momento determinado, mostrando qué tiene (activo) y cómo lo financia (pasivo y patrimonio neto). Se estructura siguiendo el Plan General de Contabilidad español en dos masas patrimoniales iguales: el activo, ordenado de menor a mayor liquidez, y el pasivo y patrimonio neto, ordenado de menor a mayor exigibilidad. El activo se divide en activo no corriente, que incluye inmovilizado material, intangible e inversiones financieras a largo plazo, y activo corriente, que agrupa existencias, deudores comerciales, inversiones financieras a corto plazo y efectivo. El patrimonio neto recoge los fondos propios: capital social, reservas, resultado del ejercicio y subvenciones. El pasivo no corriente incluye deudas a largo plazo con entidades financieras, proveedores de inmovilizado y acreedores por arrendamiento financiero, mientras que el pasivo corriente agrupa las obligaciones a corto plazo como proveedores, acreedores comerciales y deudas financieras inferiores al año. El principio fundamental que rige el balance es la ecuación contable: Activo = Patrimonio Neto + Pasivo. El análisis del balance permite calcular ratios como el fondo de maniobra (activo corriente menos pasivo corriente), el ratio de liquidez, el de solvencia y el de endeudamiento, indicadores clave para evaluar la salud financiera. Un balance bien interpretado aporta información estratégica sobre la capacidad de la empresa para hacer frente a sus obligaciones, financiar su crecimiento y generar valor para accionistas y stakeholders.',
'[{"pregunta":"¿Cómo se ordena el activo en el balance?","opciones":["De mayor a menor liquidez","De menor a mayor liquidez","Por orden alfabético","Por tamaño de la cuenta"],"correcta":1},{"pregunta":"¿Qué incluye el patrimonio neto?","opciones":["Solo deudas","Capital, reservas, resultado y subvenciones","Proveedores y acreedores","Inmovilizado material"],"correcta":1},{"pregunta":"¿Cuál es la ecuación contable básica?","opciones":["Activo = Ingresos - Gastos","Activo = Patrimonio Neto + Pasivo","Activo = Ventas × Margen","Activo = Capital × Reservas"],"correcta":1},{"pregunta":"¿Qué es el fondo de maniobra?","opciones":["Capital social menos reservas","Activo corriente menos pasivo corriente","Ingresos menos gastos","Patrimonio neto menos deudas"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La cuenta de pérdidas y ganancias', 'La cuenta de pérdidas y ganancias, también llamada cuenta de resultados, es el estado financiero que informa del resultado económico obtenido por la empresa durante un ejercicio, explicando cómo se ha generado. A diferencia del balance, que ofrece una foto fija en un momento dado, la cuenta de resultados es dinámica y acumula flujos durante un periodo, normalmente el año natural. Se estructura por naturaleza siguiendo el Plan General de Contabilidad y distingue varios márgenes intermedios que facilitan el análisis. El importe neto de la cifra de negocios recoge las ventas y prestaciones de servicios deducidas devoluciones y descuentos. Restando los aprovisionamientos se obtiene el margen bruto; restando los gastos de personal, otros gastos de explotación y las amortizaciones se llega al resultado de explotación o EBIT, indicador clave de la rentabilidad operativa. Los ingresos y gastos financieros determinan el resultado financiero, que sumado al de explotación da el resultado antes de impuestos. Descontado el impuesto sobre beneficios se obtiene el resultado del ejercicio, que puede ser beneficio (aumenta el patrimonio) o pérdida (lo disminuye). El análisis vertical y horizontal de la cuenta de resultados permite calcular indicadores como el margen bruto, el margen operativo, el ROE y el ROA, comparar ejercicios consecutivos y detectar tendencias. La interpretación conjunta con el balance es imprescindible para valorar la eficiencia económica, la capacidad de generación de caja y la sostenibilidad de los beneficios a largo plazo. Estos datos alimentan la toma de decisiones de dirección, inversores y acreedores.',
'[{"pregunta":"¿Qué refleja la cuenta de pérdidas y ganancias?","opciones":["El patrimonio en un momento","El resultado económico del ejercicio","La tesorería actual","El valor de mercado"],"correcta":1},{"pregunta":"¿Qué es el EBIT?","opciones":["Beneficio neto final","Resultado de explotación","Capital inmovilizado","Ingresos financieros"],"correcta":1},{"pregunta":"¿Cómo se obtiene el margen bruto?","opciones":["Ventas menos aprovisionamientos","Ventas menos impuestos","Ingresos menos amortización","Ventas más financieros"],"correcta":0},{"pregunta":"¿Qué indicador mide la rentabilidad de los fondos propios?","opciones":["ROA","ROE","EBIT","Margen bruto"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La selección de inversiones: VAN y TIR', 'La selección de inversiones es una de las decisiones más relevantes de la dirección financiera, ya que compromete recursos a largo plazo y condiciona la capacidad futura de generación de valor. Los métodos dinámicos de valoración de inversiones tienen en cuenta el valor temporal del dinero, esto es, el principio de que un euro hoy vale más que un euro mañana, debido a la inflación, al riesgo y al coste de oportunidad del capital. El Valor Actual Neto (VAN) es el criterio más riguroso y consiste en calcular el valor presente de todos los flujos de caja generados por la inversión, descontados a una tasa que refleja el coste del capital, y restar el desembolso inicial. Un VAN positivo indica que la inversión crea valor y debe aceptarse; uno negativo implica destrucción de valor y debe rechazarse; un VAN nulo indica indiferencia. La Tasa Interna de Rentabilidad (TIR) es aquel tipo de descuento que iguala el VAN a cero, es decir, la rentabilidad intrínseca que ofrece la inversión. Se compara con el coste del capital o con una tasa de corte: si la TIR es superior, la inversión es aceptable. Ambos criterios son complementarios y suelen coincidir en proyectos sencillos, pero pueden diferir en casos con flujos irregulares o múltiples cambios de signo, donde el VAN resulta más fiable. Además existen criterios estáticos como el plazo de recuperación o pay-back, que no consideran el valor temporal pero resultan sencillos. Una correcta valoración exige estimar flujos con realismo y elegir un tipo de descuento coherente con el riesgo.',
'[{"pregunta":"¿Qué principio subyace a los métodos dinámicos?","opciones":["El dinero no cambia de valor","Un euro hoy vale más que un euro mañana","Los flujos son siempre iguales","El riesgo no influye"],"correcta":1},{"pregunta":"¿Qué indica un VAN positivo?","opciones":["Destrucción de valor","Creación de valor: aceptar","Indiferencia","Pérdida económica"],"correcta":1},{"pregunta":"¿Qué es la TIR?","opciones":["El tipo que hace VAN = 0","El tipo impuesto por el banco","Un ratio contable","El coste fijo de la inversión"],"correcta":0},{"pregunta":"¿Qué criterio es más fiable con flujos irregulares?","opciones":["El pay-back","La TIR","El VAN","El margen bruto"],"correcta":2}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El marketing mix y las 4P', 'El marketing mix es el conjunto de herramientas tácticas que la empresa combina para influir en la demanda de su producto en el mercado objetivo. El modelo clásico de las 4P, formulado por Jerome McCarthy en los años sesenta, engloba cuatro variables controlables por la dirección: producto, precio, distribución (placement) y comunicación (promotion). El producto abarca no solo el bien físico o servicio prestado, sino también los atributos intangibles: marca, envase, diseño, garantía, servicio postventa y gama. Su gestión exige decidir sobre el posicionamiento, el ciclo de vida, la diferenciación y la innovación. El precio es la única variable que genera ingresos directamente y debe fijarse considerando costes, demanda, competencia, percepciones del consumidor y objetivos estratégicos; técnicas como el precio psicológico, la discriminación de precios o las rebajas por volumen permiten afinar la política. La distribución consiste en hacer llegar el producto al cliente en el momento, lugar y cantidad adecuados, eligiendo entre canales cortos, largos o directos, evaluando la cobertura y la logística. La comunicación engloba las herramientas de promoción: publicidad, relaciones públicas, venta personal, promoción de ventas y marketing digital, orientadas a informar, persuadir y recordar. La coherencia entre las 4P es esencial para crear valor: un producto innovador con un precio inadecuado o una distribución limitada fracasará. El marketing contemporáneo extiende las 4P con nuevas variables como personas, procesos y evidencia física en servicios, y cuestiona el modelo frente a las 4C centradas en el cliente, orientadas a la experiencia y al valor percibido.',
'[{"pregunta":"¿Quién formuló el modelo de las 4P?","opciones":["Philip Kotler","Jerome McCarthy","Michael Porter","Peter Drucker"],"correcta":1},{"pregunta":"¿Qué variable del marketing genera ingresos directamente?","opciones":["Producto","Precio","Distribución","Comunicación"],"correcta":1},{"pregunta":"¿Qué incluye el producto en su dimensión intangible?","opciones":["Marca, envase, servicio postventa","Solo el bien físico","Solo los costes","El canal de distribución"],"correcta":0},{"pregunta":"¿Qué complementa el modelo en servicios?","opciones":["Ingresos, costes, beneficios","Personas, procesos, evidencia física","Pasivo, activo, neto","VAN, TIR, pay-back"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La función de producción y los costes', 'La función de producción describe la relación técnica entre los factores productivos utilizados por la empresa (trabajo, capital, materias primas, tecnología) y el output obtenido. Permite analizar la eficiencia, calcular costes, determinar el tamaño óptimo de planta y tomar decisiones sobre combinaciones alternativas de factores. A corto plazo, con al menos un factor fijo, rige la ley de rendimientos decrecientes: a partir de cierto punto, cada unidad adicional del factor variable genera un producto marginal cada vez menor. A largo plazo, todos los factores son variables y la empresa puede experimentar economías de escala, cuando el coste medio disminuye al aumentar la producción, aprovechando la especialización, la indivisibilidad técnica, las compras en volumen o la curva de aprendizaje. Por el contrario, pueden aparecer deseconomías de escala si el crecimiento excesivo genera burocratización, pérdida de control, problemas de coordinación o desmotivación. Los costes de producción se clasifican en fijos, que no varían con el volumen (alquileres, amortizaciones, salarios directivos), y variables, que sí dependen del nivel de actividad (materias primas, suministros, mano de obra directa). La suma de ambos es el coste total, y dividido entre el número de unidades da el coste medio o unitario. El coste marginal es el incremento de coste total al producir una unidad adicional. El umbral de rentabilidad o punto muerto es aquel nivel de producción donde los ingresos igualan a los costes totales, es decir, donde el beneficio es cero. A partir de él la empresa comienza a obtener beneficios, siendo un indicador esencial de viabilidad.',
'[{"pregunta":"¿Qué ley rige la producción a corto plazo?","opciones":["Rendimientos crecientes ilimitados","Rendimientos decrecientes","Coste cero marginal","Ingreso total constante"],"correcta":1},{"pregunta":"¿Qué son las economías de escala?","opciones":["Aumento del coste medio con producción","Disminución del coste medio al aumentar producción","Coste fijo total","Ingresos marginales"],"correcta":1},{"pregunta":"¿Qué son los costes fijos?","opciones":["Los que dependen del volumen","Los que no varían con la producción","Los costes de materias primas","Los costes financieros"],"correcta":1},{"pregunta":"¿Qué indica el umbral de rentabilidad?","opciones":["Nivel donde ingresos = costes totales","Máxima producción posible","Coste medio mínimo","Beneficio máximo"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La dirección estratégica y el análisis DAFO', 'La dirección estratégica consiste en definir y ejecutar las decisiones de largo plazo que determinan el rumbo, el ámbito de actividad y la ventaja competitiva de la empresa en su entorno. Su objetivo es crear valor de forma sostenida, adaptando continuamente la organización a un entorno cambiante y complejo. El proceso estratégico clásico parte del análisis externo e interno, define la misión, visión y valores, formula estrategias corporativas, competitivas y funcionales, las implanta mediante planes operativos y las controla mediante indicadores. El análisis externo examina el macroentorno, utilizando herramientas como el análisis PESTEL (factores políticos, económicos, sociales, tecnológicos, ecológicos y legales), y el entorno específico o sectorial, mediante el modelo de las cinco fuerzas de Porter: rivalidad entre competidores, amenaza de nuevos entrantes, amenaza de productos sustitutivos, poder negociador de clientes y proveedores. El análisis interno identifica recursos tangibles e intangibles, capacidades, cadena de valor y competencias distintivas, determinando fortalezas y debilidades. La herramienta DAFO sintetiza el diagnóstico al cruzar las oportunidades y amenazas del entorno con las fortalezas y debilidades propias, permitiendo definir estrategias ofensivas (F-O), defensivas (F-A), de reorientación (D-O) y de supervivencia (D-A). La matriz CAME complementa al DAFO indicando cómo corregir debilidades, afrontar amenazas, mantener fortalezas y explotar oportunidades. Una estrategia exitosa requiere coherencia, flexibilidad, compromiso de la alta dirección, implicación de los empleados y capacidad de aprendizaje organizativo, en un proceso continuo que no se limita a formular, sino que se revisa y actualiza constantemente.',
'[{"pregunta":"¿Qué analiza PESTEL?","opciones":["Solo lo económico","El macroentorno en múltiples dimensiones","La estructura contable","El balance"],"correcta":1},{"pregunta":"¿Cuántas fuerzas identifica Porter?","opciones":["Tres","Cinco","Siete","Diez"],"correcta":1},{"pregunta":"¿Qué combina el análisis DAFO?","opciones":["Ingresos y gastos","Interno (FD) y externo (OA)","Activo y pasivo","Producción y ventas"],"correcta":1},{"pregunta":"¿Qué hace la matriz CAME?","opciones":["Sustituye al DAFO","Complementa al DAFO indicando acciones","Es una cuenta contable","Mide el VAN"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La gestión de los recursos humanos', 'La gestión de los recursos humanos ha evolucionado desde una concepción tradicional centrada en la administración de personal (nóminas, contratos, disciplina) hacia una visión estratégica que considera a las personas como el principal activo de la empresa y una fuente sostenible de ventaja competitiva. Las funciones básicas incluyen la planificación de plantillas, el reclutamiento y selección, la formación y desarrollo, la evaluación del desempeño, la política retributiva, la gestión de la carrera profesional, la motivación, la comunicación interna y las relaciones laborales. El reclutamiento puede ser interno, aprovechando el talento existente mediante promoción, o externo, buscando candidatos fuera mediante portales de empleo, redes profesionales, headhunting o prácticas universitarias. La selección utiliza técnicas como pruebas psicotécnicas, entrevistas estructuradas, dinámicas de grupo y assessment centers. La formación es clave para adaptar competencias a los cambios tecnológicos y organizativos, y puede ser inicial, continua, interna o externa. La motivación de los empleados se apoya en teorías clásicas como la jerarquía de necesidades de Maslow, los factores higiene-motivación de Herzberg, la teoría de la equidad de Adams o la teoría de la autodeterminación, que combinan retribución, reconocimiento, autonomía, desarrollo y sentido del propósito. El liderazgo y la cultura organizativa modulan el compromiso y el rendimiento. En la actualidad, la gestión de personas se enfrenta a retos como la diversidad, la conciliación, el teletrabajo, la salud mental, la transformación digital, la gestión del talento multigeneracional y la atracción de profesionales altamente cualificados, lo que exige políticas innovadoras, éticas e inclusivas.',
'[{"pregunta":"¿Cómo ha evolucionado la función de RRHH?","opciones":["Se ha suprimido","De administrativa a estratégica","De estratégica a burocrática","Se ha externalizado por completo"],"correcta":1},{"pregunta":"¿Qué teoría clasifica necesidades en jerarquía?","opciones":["Herzberg","Maslow","Porter","Drucker"],"correcta":1},{"pregunta":"¿Qué técnica de selección es un assessment center?","opciones":["Un contrato laboral","Una dinámica evaluativa de competencias","Un sistema de nóminas","Un tipo de despido"],"correcta":1},{"pregunta":"¿Qué reto actual de RRHH menciona el texto?","opciones":["Trabajo infantil","Teletrabajo y talento multigeneracional","Jornada ilimitada","Ausencia de digitalización"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Las fuentes de financiación empresarial', 'La financiación empresarial consiste en la obtención de los recursos necesarios para acometer inversiones y cubrir necesidades operativas, y se clasifica según su origen (propia o ajena), su plazo (corto o largo) y su procedencia (interna o externa). La financiación propia incluye el capital aportado por los socios (capital social, ampliaciones, primas de emisión) y la autofinanciación, generada por el propio funcionamiento de la empresa mediante beneficios retenidos en reservas, amortizaciones y provisiones. La autofinanciación refuerza la solvencia, reduce la dependencia exterior y mejora la independencia financiera. La financiación ajena procede de terceros que esperan una remuneración y la devolución del capital. A largo plazo encontramos préstamos bancarios, empréstitos u obligaciones, leasing y renting, subvenciones y financiación pública. A corto plazo se utilizan créditos comerciales de proveedores, descuentos comerciales, factoring, confirming, anticipos de clientes, líneas de crédito y pólizas. La elección óptima depende del coste, el riesgo, la flexibilidad, el equilibrio entre deuda y fondos propios y el efecto sobre la estructura financiera. El principio de equilibrio financiero establece que las inversiones a largo plazo deben financiarse con recursos permanentes (patrimonio neto y pasivo no corriente), mientras que las necesidades corrientes pueden cubrirse con pasivo corriente, garantizando un fondo de maniobra positivo. El ratio de endeudamiento mide la proporción de deuda, indicando el apalancamiento financiero, que amplifica tanto las ganancias como las pérdidas. Formas emergentes como el crowdfunding, los business angels, el capital riesgo o las plataformas fintech amplían hoy el abanico de opciones, especialmente para startups y proyectos innovadores con modelos escalables.',
'[{"pregunta":"¿Qué es la autofinanciación?","opciones":["Préstamos bancarios","Financiación generada por la propia empresa","Subvenciones públicas","Capital de terceros"],"correcta":1},{"pregunta":"¿Qué financiación corresponde al factoring?","opciones":["A largo plazo","A corto plazo","A muy largo plazo","Es capital propio"],"correcta":1},{"pregunta":"¿Qué establece el principio de equilibrio financiero?","opciones":["Todo debe financiarse a corto","Inversiones a largo con recursos permanentes","No usar deuda","No usar capital propio"],"correcta":1},{"pregunta":"¿Qué forma emergente menciona el texto?","opciones":["Trueque","Crowdfunding","Sociedad colectiva","Empréstito medieval"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El plan de empresa', 'El plan de empresa o business plan es el documento que recoge de forma estructurada y sistemática la idea de negocio, el análisis del entorno, la estrategia, los objetivos, la organización interna y las previsiones económico-financieras de un proyecto empresarial. Constituye una herramienta imprescindible tanto para el emprendedor, que le permite validar su idea, anticipar obstáculos y planificar recursos, como para terceros (inversores, entidades financieras, socios, administraciones) a los que se presenta en busca de apoyo. Su estructura típica incluye un resumen ejecutivo que sintetiza los aspectos clave, la presentación de los promotores y la descripción del producto o servicio, el análisis de mercado con segmentación de clientes, estudio de la competencia y estimación de la demanda, el plan de marketing con política de producto, precio, distribución y comunicación, el plan de operaciones que detalla procesos, localización, proveedores y recursos técnicos, el plan de recursos humanos con organigrama, perfiles y política retributiva, el plan jurídico-fiscal con forma societaria, licencias e implicaciones tributarias, y el plan económico-financiero, probablemente el apartado más escrutado, que recoge inversión inicial, fuentes de financiación, previsiones de tesorería, cuenta de resultados proyectada, balance previsional y análisis de viabilidad con cálculo del umbral de rentabilidad, VAN y TIR. Además, un buen plan debe contemplar un análisis de riesgos con planes de contingencia y un calendario de implantación realista. El plan de empresa no es un documento estático, sino una guía viva que se revisa y actualiza a medida que la empresa avanza, aprende del mercado y ajusta su rumbo estratégico.',
'[{"pregunta":"¿Qué es el resumen ejecutivo?","opciones":["Un anexo legal","Una síntesis inicial de los aspectos clave","La cuenta de resultados","El organigrama"],"correcta":1},{"pregunta":"¿Qué incluye el plan económico-financiero?","opciones":["Solo el organigrama","Inversión, financiación, VAN, TIR, balance","Contratos laborales","Plan de marketing"],"correcta":1},{"pregunta":"¿Para quién es útil el plan de empresa?","opciones":["Solo para el emprendedor","Emprendedor, inversores, financieros, socios","Solo para Hacienda","Solo para proveedores"],"correcta":1},{"pregunta":"¿Cómo debe entenderse el plan?","opciones":["Documento inmutable","Guía viva que se actualiza","Mera formalidad","Solo un papel legal"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La responsabilidad social corporativa', 'La responsabilidad social corporativa (RSC) es el compromiso voluntario que asumen las empresas para integrar en sus estrategias y operaciones preocupaciones sociales, ambientales y éticas que van más allá de las obligaciones legales. Nace de la constatación de que la actividad empresarial genera impactos positivos y negativos sobre múltiples grupos de interés o stakeholders: accionistas, empleados, clientes, proveedores, comunidades locales, administraciones públicas y medio ambiente. La RSC se sustenta en la idea de que la sostenibilidad a largo plazo exige equilibrar la rentabilidad económica con la justicia social y la preservación ambiental, conocido como el triple balance o triple bottom line. Las áreas de actuación suelen incluir buen gobierno corporativo, transparencia, lucha contra la corrupción, derechos humanos en la cadena de suministro, igualdad y diversidad, conciliación, seguridad y salud laboral, innovación sostenible, economía circular, reducción de emisiones y huella de carbono, gestión del agua, eficiencia energética, acción social y colaboración con el tercer sector. La RSC se instrumenta mediante códigos éticos, memorias de sostenibilidad elaboradas conforme a estándares internacionales como el Global Reporting Initiative (GRI), certificaciones como la ISO 26000, la adhesión al Pacto Mundial de Naciones Unidas o los Objetivos de Desarrollo Sostenible de la Agenda 2030. La nueva directiva europea de reporting de sostenibilidad (CSRD) obliga a las grandes empresas a publicar información no financiera verificable. Bien implementada, la RSC mejora la reputación, fideliza clientes, motiva empleados, reduce riesgos regulatorios, facilita el acceso a capital sostenible y contribuye a construir un modelo económico más justo y habitable para las generaciones futuras.',
'[{"pregunta":"¿Qué es el triple balance o triple bottom line?","opciones":["Balance bancario triple","Equilibrio entre lo económico, social y ambiental","Tres cuentas bancarias","Un ratio contable"],"correcta":1},{"pregunta":"¿Qué estándar menciona el texto para memorias de sostenibilidad?","opciones":["GRI","PGC","NIIF","PIB"],"correcta":0},{"pregunta":"¿Quiénes son los stakeholders?","opciones":["Solo los accionistas","Todos los grupos de interés","Los directivos","Los auditores"],"correcta":1},{"pregunta":"¿Qué directiva europea obliga al reporting no financiero?","opciones":["MIFID","CSRD","GDPR","RGPD"],"correcta":1}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La globalización y la internacionalización', 'La globalización ha transformado radicalmente el escenario empresarial de las últimas décadas, integrando mercados, acortando distancias y generando una creciente interdependencia económica entre países. Para las empresas, la internacionalización se ha convertido en una estrategia imprescindible para crecer, diversificar riesgos, aprovechar oportunidades, ganar competitividad y acceder a recursos, conocimientos y mercados que el ámbito local no ofrece. Las motivaciones para internacionalizarse incluyen la saturación del mercado interno, la búsqueda de economías de escala, el aprovechamiento de ventajas en costes, la diversificación geográfica del riesgo, el seguimiento de clientes que operan internacionalmente y la presión competitiva. Los modos de entrada se ordenan según su grado de implicación: exportación directa o indirecta, acuerdos contractuales como licencias, franquicias o contratos de fabricación, alianzas estratégicas y joint ventures con socios locales, e inversión directa mediante filiales comerciales o productivas. Cada opción implica distintos niveles de control, inversión, riesgo y rentabilidad potencial. Las empresas multinacionales organizan su actividad global mediante estructuras que pueden ser etnocéntricas, policéntricas, regiocéntricas o geocéntricas, según el grado de centralización y adaptación local. La globalización genera beneficios como mayor acceso a productos, especialización y crecimiento, pero también críticas por la deslocalización de empleos, la presión sobre derechos laborales y ambientales, la concentración de poder en grandes corporaciones, la evasión fiscal y la homogenización cultural. Las tensiones geopolíticas recientes, las disrupciones en cadenas de suministro, la sostenibilidad y el nearshoring están reconfigurando los modelos tradicionales, dando lugar a nuevos equilibrios entre globalización y soberanía económica en un mundo menos previsible.',
'[{"pregunta":"¿Qué estrategia implica menor implicación internacional?","opciones":["Filial propia","Exportación","Joint venture","Adquisición"],"correcta":1},{"pregunta":"¿Qué es una joint venture?","opciones":["Exportación indirecta","Alianza con socio local","Franquicia individual","Un tipo de impuesto"],"correcta":1},{"pregunta":"¿Qué estructura multinacional prioriza adaptación local?","opciones":["Etnocéntrica","Policéntrica","Centralizada","Taylorista"],"correcta":1},{"pregunta":"¿Qué fenómeno reciente reconfigura la globalización?","opciones":["Nearshoring y tensiones geopolíticas","Desaparición total del comercio","Retorno al trueque","Supresión de aranceles globales"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La innovación y la empresa tecnológica', 'La innovación es uno de los motores fundamentales del crecimiento económico y la competitividad empresarial en la sociedad del conocimiento. Schumpeter la definió como el proceso de destrucción creativa por el cual nuevas combinaciones productivas desplazan a las antiguas, impulsando el progreso económico. La innovación empresarial puede clasificarse en diversos tipos: de producto, al introducir un bien o servicio nuevo o mejorado; de proceso, al modificar métodos de producción o distribución; organizativa, al cambiar estructuras, prácticas o relaciones externas; y de marketing, al transformar diseño, envase, precio o comunicación. Según su intensidad, puede ser incremental, con mejoras graduales, o radical, rompedora y transformadora del mercado. Las fuentes de innovación son diversas: investigación y desarrollo interna, colaboración con universidades y centros tecnológicos, transferencia de tecnología, escucha del cliente, aprendizaje por la experiencia, vigilancia tecnológica o adquisición de empresas innovadoras. Los modelos lineales tradicionales han sido superados por enfoques sistémicos y abiertos, como la open innovation de Chesbrough, que recalca la importancia de flujos internos y externos de conocimiento. El apoyo público a la innovación se canaliza mediante programas europeos (Horizonte Europa), nacionales (CDTI) y autonómicos, con financiación, incentivos fiscales (deducción por I+D+i) y apoyo a clústeres y parques tecnológicos. Las empresas tecnológicas basan su ventaja en intangibles como software, patentes, marcas y know-how, con modelos escalables y elevada internacionalización. Los retos actuales incluyen la inteligencia artificial, la sostenibilidad, la ciberseguridad y la adaptación cultural al cambio continuo, aspectos decisivos para permanecer competitivos en un entorno acelerado y exigente.',
'[{"pregunta":"¿Quién acuñó la destrucción creativa?","opciones":["Keynes","Schumpeter","Smith","Marx"],"correcta":1},{"pregunta":"¿Qué es la innovación de proceso?","opciones":["Introducción de producto nuevo","Modificación de métodos de producción","Cambio de envase","Nueva campaña publicitaria"],"correcta":1},{"pregunta":"¿Quién propuso la open innovation?","opciones":["Porter","Chesbrough","Drucker","Kotler"],"correcta":1},{"pregunta":"¿Qué organismo nacional apoya la innovación en España?","opciones":["CDTI","CNMC","CNMV","BOE"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El crecimiento empresarial', 'El crecimiento es un objetivo recurrente de las empresas, asociado a mejoras en eficiencia, poder de mercado, reducción de costes unitarios y mayor capacidad de innovación. Existen dos grandes vías: el crecimiento interno u orgánico, basado en el incremento progresivo de las capacidades productivas mediante la reinversión de beneficios, la ampliación de instalaciones, la contratación de personal o la extensión a nuevos mercados; y el crecimiento externo, que implica la fusión con otras empresas, la adquisición total o parcial, o la creación de alianzas y acuerdos de cooperación. El crecimiento interno es más lento y prudente pero permite mayor control, mientras que el externo aporta rapidez y acceso inmediato a cuotas de mercado, marcas, tecnologías o redes comerciales, aunque conlleva mayores riesgos de integración y financieros. Las estrategias de Ansoff clasifican el crecimiento en cuatro cuadrantes: penetración de mercado (aumentar cuota en productos y mercados actuales), desarrollo de mercado (entrar en mercados nuevos con productos actuales), desarrollo de producto (lanzar productos nuevos en mercados actuales) y diversificación (nuevos productos y nuevos mercados), que puede ser relacionada o no relacionada según la proximidad con la actividad base. La integración vertical extiende la cadena de valor hacia atrás (proveedores) o hacia delante (distribuidores), mientras la integración horizontal une empresas competidoras. La subcontratación y la externalización permiten crecer liberando recursos para actividades clave. El crecimiento debe equilibrarse con la rentabilidad, la solvencia y la sostenibilidad; un crecimiento mal gestionado puede generar problemas financieros, pérdida de identidad o diseconomías organizativas.',
'[{"pregunta":"¿Qué caracteriza el crecimiento interno?","opciones":["Fusiones rápidas","Aumento progresivo propio","Adquisiciones hostiles","Alianzas externas"],"correcta":1},{"pregunta":"¿Cuántos cuadrantes tiene la matriz Ansoff?","opciones":["Dos","Cuatro","Seis","Ocho"],"correcta":1},{"pregunta":"¿Qué es la integración vertical hacia atrás?","opciones":["Unir con competidores","Extenderse hacia proveedores","Comprar distribuidores","Externalizar actividades"],"correcta":1},{"pregunta":"¿Qué riesgo tiene el crecimiento excesivo?","opciones":["Diseconomías organizativas","Aumento automático del beneficio","Reducción segura de costes","Mayor solvencia garantizada"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Los mercados y la competencia', 'Los mercados son los espacios donde confluyen oferentes y demandantes para realizar intercambios de bienes y servicios, y su análisis constituye un elemento esencial de la economía de la empresa. Los mercados pueden clasificarse según diversos criterios: por el producto (bienes de consumo, industriales, financieros), por el ámbito geográfico (local, regional, nacional, internacional), por la naturaleza del comprador (mayorista, minorista, institucional) o por el grado de competencia. Desde la perspectiva de la competencia, se distinguen cuatro estructuras principales. La competencia perfecta es un modelo teórico caracterizado por un gran número de oferentes y demandantes, producto homogéneo, libre entrada y salida, información perfecta y precios aceptados por todos. El monopolio es la situación opuesta: un único vendedor con capacidad para fijar el precio, a menudo protegido por barreras legales, tecnológicas, patentes o control de recursos esenciales. El oligopolio se caracteriza por pocos vendedores con poder significativo, interdependencia estratégica y producto homogéneo o diferenciado; ejemplos típicos son el sector energético, las telecomunicaciones o la automoción. La competencia monopolística combina muchos oferentes con producto diferenciado por marca, calidad o diseño, permitiendo cierto margen en el precio; es frecuente en el comercio, restauración y servicios. Estas estructuras influyen decisivamente en el comportamiento empresarial, las políticas de precios, la innovación y el bienestar del consumidor. La Comisión Nacional de los Mercados y la Competencia (CNMC) en España y la Comisión Europea vigilan la competencia, sancionan los cárteles, abusos de posición dominante y concentraciones lesivas, garantizando un funcionamiento eficiente y transparente de los mercados.',
'[{"pregunta":"¿Qué caracteriza la competencia perfecta?","opciones":["Un único vendedor","Muchos oferentes y producto homogéneo","Poder del vendedor","Ausencia de demanda"],"correcta":1},{"pregunta":"¿Qué estructura tiene pocos vendedores interdependientes?","opciones":["Monopolio","Oligopolio","Competencia perfecta","Autarquía"],"correcta":1},{"pregunta":"¿Qué combina la competencia monopolística?","opciones":["Un solo vendedor y precios fijos","Muchos oferentes con producto diferenciado","Pocos vendedores homogéneos","Ausencia de marcas"],"correcta":1},{"pregunta":"¿Qué organismo español vigila la competencia?","opciones":["CNMV","CNMC","BDE","ICO"],"correcta":1}]'::jsonb);

