INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ingles', 'bachillerato', '{2}', 'The Rise of Renewable Energy', 'Over the past two decades, renewable energy has transformed from a marginal alternative into a central pillar of global energy strategy. Driven by falling technology costs, ambitious climate policies and growing public awareness, wind and solar power now account for a substantial share of electricity generation in many countries. The International Energy Agency reports that renewables overtook coal as the leading source of new power capacity worldwide in 2023, a milestone that would have seemed improbable just a generation ago. Solar photovoltaic panels, whose prices have dropped by more than ninety per cent since 2010, are being installed at an unprecedented pace in regions ranging from sunny deserts to rooftops in cloudy northern cities. Wind turbines, both onshore and offshore, have grown taller and more efficient, enabling projects in locations once considered unsuitable. However, the transition is not without challenges. Intermittency remains a fundamental issue: the sun does not always shine, nor does the wind always blow. Storage technologies such as lithium-ion batteries, pumped hydro and emerging hydrogen solutions are critical to ensuring a reliable supply. Grid infrastructure often requires substantial upgrades to integrate decentralised sources and manage variable flows. Moreover, the environmental and social impacts of extracting minerals for batteries and panels raise uncomfortable questions about fairness and sustainability. Despite these obstacles, momentum is unmistakable. Governments, investors and citizens increasingly recognise that the shift to renewables is not only an environmental imperative but also an economic opportunity, capable of creating jobs, enhancing energy security and reducing long-term costs for consumers worldwide.',
'[{"pregunta":"What milestone did renewables reach in 2023?","opciones":["They replaced all fossil fuels","They overtook coal as leading source of new power capacity","They became cheaper than oil","They were banned in some countries"],"correcta":1},{"pregunta":"How much have solar PV prices dropped since 2010?","opciones":["About 20 per cent","More than 90 per cent","Around 50 per cent","They have risen"],"correcta":1},{"pregunta":"What is described as a fundamental challenge of renewables?","opciones":["High installation speed","Intermittency","Lack of public support","Too much storage"],"correcta":1},{"pregunta":"What do the final lines suggest about the transition?","opciones":["It is unnecessary","It offers both environmental and economic benefits","It benefits only wealthy nations","It has failed entirely"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Artificial Intelligence and the Future of Work', 'The rapid development of artificial intelligence has sparked passionate debates about its implications for the labour market. Optimists argue that AI will liberate workers from repetitive and dangerous tasks, boost productivity and generate entirely new professions, much as previous technological revolutions eventually created more jobs than they destroyed. Pessimists warn that this time is different, as AI encroaches not only on manual labour but also on cognitive work once thought exclusively human, including writing, coding, analysis and even creative endeavours. Recent studies by major consulting firms estimate that between twenty and forty per cent of current job tasks could be automated within the next decade, though the actual impact will vary enormously across sectors, regions and income levels. What seems increasingly clear is that the transformation will not be uniform. Routine cognitive roles in fields such as accounting, legal research and customer service are particularly exposed, while jobs requiring emotional intelligence, manual dexterity in unstructured environments or complex social interaction appear more resilient. A critical question is whether displaced workers can reskill quickly enough to take advantage of emerging opportunities. History suggests that adaptation is possible but rarely painless: transitions often leave vulnerable groups behind unless accompanied by deliberate policy measures. Education systems, lifelong learning programmes and social safety nets will need substantial reform to cope with a faster pace of change. The ethical dimensions also deserve attention: who owns the data AI systems are trained on, who profits from the productivity gains, and how do we ensure that the benefits are shared equitably rather than concentrated in a handful of technology companies?',
'[{"pregunta":"What do optimists claim about AI?","opciones":["It will destroy all jobs","It will free workers from repetitive tasks","It will make humans obsolete","It is irrelevant"],"correcta":1},{"pregunta":"Which roles are described as more resilient to automation?","opciones":["Routine accounting","Customer service","Those requiring emotional intelligence and complex social interaction","Legal research"],"correcta":2},{"pregunta":"What percentage of tasks could be automated in the next decade?","opciones":["Between 1 and 5 per cent","Between 20 and 40 per cent","About 80 per cent","None"],"correcta":1},{"pregunta":"What ethical issue is raised at the end?","opciones":["How benefits are shared","Whether robots need rights","Whether AI can feel","Whether data is stored"],"correcta":0}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Shakespeare and the Power of Language', 'William Shakespeare, born in Stratford-upon-Avon in 1564, remains arguably the most influential figure in English literature more than four centuries after his death. His works, comprising at least thirty-eight plays, 154 sonnets and several narrative poems, continue to be performed, studied and reimagined across every continent. Yet Shakespeare was not only a master storyteller; he was also a linguistic innovator whose legacy pervades everyday English. Scholars estimate that he introduced or popularised around 1,700 words and countless expressions that have become proverbial, from "break the ice" and "heart of gold" to "wild-goose chase" and "in a pickle". His capacity to capture the contradictions of human nature, the tension between ambition and conscience in Macbeth, the madness of grief in King Lear, the uncertainty of existence in Hamlet, gives his characters a psychological depth that feels remarkably contemporary. Despite being rooted in the political, religious and social tensions of Elizabethan and Jacobean England, his plays resonate with audiences today because they explore universal themes: love, jealousy, power, betrayal, forgiveness and the fragility of identity. Modern productions often transpose the action to radically different settings, from Nazi Germany to corporate boardrooms, without compromising the emotional impact. Shakespeare also played a decisive role in shaping the flexibility and richness of modern English, demonstrating how the language could accommodate philosophical reflection, bawdy humour and lyrical beauty within the same work. His continued influence on drama, cinema, music and everyday speech is a testament to the extraordinary adaptability and enduring relevance of his vision, even in a world he could never have imagined.',
'[{"pregunta":"Where was Shakespeare born?","opciones":["London","Stratford-upon-Avon","Oxford","Canterbury"],"correcta":1},{"pregunta":"Approximately how many words did he introduce or popularise?","opciones":["Around 200","Around 1,700","Over 10,000","Fewer than 50"],"correcta":1},{"pregunta":"Why do modern audiences still relate to his plays?","opciones":["They are easy to read","They explore universal human themes","They avoid any conflict","They are set in modern times"],"correcta":1},{"pregunta":"What does the text say about modern productions?","opciones":["They always preserve original settings","They often transpose the action to different contexts","They ignore the characters","They rewrite the dialogue completely"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Climate Change and Coastal Cities', 'Coastal cities around the world are increasingly vulnerable to the consequences of climate change, facing rising sea levels, more intense storms, coastal erosion and saltwater intrusion into freshwater supplies. According to the Intergovernmental Panel on Climate Change, global sea levels could rise by up to one metre by the end of the twenty-first century if greenhouse gas emissions are not drastically reduced. Such a rise would threaten the livelihoods of hundreds of millions of people who live in low-lying urban areas, including megacities like Jakarta, Lagos, Mumbai, Dhaka, New York, Miami and Shanghai. Jakarta, the capital of Indonesia, is sinking so rapidly due to a combination of sea-level rise and excessive groundwater extraction that the government has decided to relocate administrative functions to a new inland capital. In other cities, authorities are investing in seawalls, flood barriers, elevated roads and nature-based solutions such as mangrove restoration and coastal wetlands. The Dutch, with centuries of experience managing water, have become global experts, sharing their techniques through international cooperation programmes. Yet technical solutions alone are insufficient without addressing the root cause: carbon emissions driven largely by fossil fuel combustion. Mitigation through renewable energy, energy efficiency and sustainable transport must proceed alongside adaptation measures if coastal cities are to remain habitable. Vulnerable populations, often lacking the resources to relocate or protect their homes, bear the brunt of impacts, raising urgent issues of climate justice. The decisions made in the next decade will determine whether coastal urban civilisation adapts successfully or confronts unprecedented displacement and loss in the coming century.',
'[{"pregunta":"How much could sea levels rise by 2100 according to the IPCC?","opciones":["Up to one metre","Five metres","Ten centimetres","They will not rise"],"correcta":0},{"pregunta":"Why is Jakarta relocating its administrative functions?","opciones":["Because of air pollution","Because it is sinking rapidly","Because of earthquakes","Because of population decline"],"correcta":1},{"pregunta":"Which country is mentioned as a global water management expert?","opciones":["Japan","The Netherlands","Brazil","Russia"],"correcta":1},{"pregunta":"What does the text imply about vulnerable populations?","opciones":["They always adapt easily","They face greater impacts and climate injustice","They are not affected","They move first"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Evolution of Social Media', 'Social media platforms, which barely existed two decades ago, have become an integral part of daily life for billions of people around the world. From MySpace and early blogging tools to Facebook, YouTube, Instagram, TikTok and countless others, these networks have revolutionised how people communicate, share information, form relationships and perceive themselves. They have enabled grassroots movements to mobilise supporters quickly, allowed distant families to remain in contact and given amateur creators unprecedented opportunities to reach global audiences. Yet the benefits come with significant drawbacks that are only now being fully recognised. Studies increasingly link heavy social media use, particularly among adolescents, to rising rates of anxiety, depression, sleep disturbance and low self-esteem. Algorithms designed to maximise engagement often amplify sensational, divisive or misleading content, contributing to political polarisation and the spread of misinformation. The attention economy rewards outrage over nuance and speed over accuracy, undermining public discourse. Additionally, concerns about data privacy, surveillance and the immense power concentrated in a handful of technology companies have prompted calls for stricter regulation in many jurisdictions. The European Union, in particular, has adopted comprehensive legislation requiring greater transparency, user control and accountability. Meanwhile, users themselves are reconsidering their relationship with these platforms, experimenting with digital detox, setting screen-time limits and seeking alternatives that prioritise well-being over engagement. The debate over social media reflects a broader question about technology in society: how to harness its extraordinary benefits while protecting individuals and democratic institutions from its potential harms in an increasingly interconnected world.',
'[{"pregunta":"What has been linked to heavy use by adolescents?","opciones":["Improved academic results","Higher rates of anxiety and depression","Better sleep","Reduced creativity only"],"correcta":1},{"pregunta":"What do algorithms often amplify?","opciones":["Only positive content","Sensational and divisive content","Scientific accuracy","Educational material"],"correcta":1},{"pregunta":"What has the European Union done about these issues?","opciones":["Banned all platforms","Adopted comprehensive legislation","Nothing so far","Subsidised social media"],"correcta":1},{"pregunta":"What does the text suggest users are doing now?","opciones":["Reconsidering their relationship with platforms","Using them more than ever","Abandoning the internet entirely","Ignoring the problem"],"correcta":0}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Industrial Revolution: Origins and Impact', 'The Industrial Revolution, which began in Britain in the second half of the eighteenth century, is widely regarded as one of the most profound transformations in human history. Within a few generations, societies that had relied for millennia on agriculture, manual craftsmanship and animal power were reshaped by mechanised factories, steam engines and railways. Britain offered a unique combination of conditions that made it the cradle of industrialisation: abundant coal reserves, a network of navigable rivers and canals, relatively stable political institutions, a strong financial system, access to colonial markets and a culture that valued practical innovation. Inventions such as the spinning jenny, the water frame, the power loom and, above all, James Watt is improved steam engine, dramatically increased productivity in textiles, metallurgy and transport. Cities grew at extraordinary speed as rural populations migrated in search of factory jobs, often enduring harsh working conditions, long hours, child labour and polluted environments. The social consequences were far-reaching and ambivalent. On the one hand, industrialisation eventually raised living standards, expanded the middle class and created new opportunities for education and social mobility. On the other, it generated stark inequalities, triggered waves of protest and inspired critical thinkers from Karl Marx to Charles Dickens to denounce its injustices. The revolution also laid the foundations for modern environmental problems, as the burning of coal contributed to the rise in atmospheric carbon dioxide. Understanding this pivotal period is essential for interpreting the contemporary world, since many of the debates about technology, inequality and sustainability that we face today have deep roots in the industrial age.',
'[{"pregunta":"Where did the Industrial Revolution begin?","opciones":["France","Germany","Britain","United States"],"correcta":2},{"pregunta":"Which inventor is explicitly mentioned?","opciones":["Thomas Edison","James Watt","Isaac Newton","Charles Darwin"],"correcta":1},{"pregunta":"What were the social consequences described?","opciones":["Entirely positive","Entirely negative","Far-reaching and ambivalent","Insignificant"],"correcta":2},{"pregunta":"What modern problem does the text connect to the era?","opciones":["Atmospheric CO2 rise","Digital addiction","Space exploration","Genetic engineering"],"correcta":0}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Bilingualism and the Human Brain', 'Decades of research have challenged the once common assumption that being raised with more than one language would confuse children and impair their cognitive development. On the contrary, contemporary studies in linguistics, psychology and neuroscience increasingly suggest that bilingualism, or multilingualism, confers significant advantages on the brain throughout life. Bilingual individuals are constantly required to select one language and suppress the other, a process that appears to strengthen the executive functions of the brain, including attention, task-switching and problem-solving. Research led by psycholinguists such as Ellen Bialystok has shown that bilingual children often perform better on tasks that demand cognitive flexibility, while older bilingual adults may experience the onset of dementia several years later than their monolingual peers. This delay, which does not prevent the disease but postpones its symptoms, is thought to result from a cognitive reserve built up over years of managing two linguistic systems. Bilingualism also offers cultural benefits, enabling speakers to engage directly with different communities, literatures and traditions, and fostering a more flexible, empathetic worldview. In an increasingly globalised and interconnected society, these advantages are economic as well as personal, since multilingual workers are in high demand in fields ranging from diplomacy to business, education and scientific research. However, some researchers caution that the cognitive benefits should not be overstated, as other factors such as education, socioeconomic background and overall lifestyle also play crucial roles. The consensus is nonetheless clear: learning and maintaining more than one language is a valuable investment in both individual development and social cohesion in diverse communities worldwide.',
'[{"pregunta":"What was once assumed about bilingual children?","opciones":["They would be more intelligent","It would confuse them","They would learn faster","They could not speak any language"],"correcta":1},{"pregunta":"What process strengthens executive functions?","opciones":["Watching television","Selecting one language and suppressing the other","Sleeping more","Ignoring grammar"],"correcta":1},{"pregunta":"What advantage do older bilinguals show?","opciones":["Faster vision","Delayed onset of dementia symptoms","Higher IQ","Stronger muscles"],"correcta":1},{"pregunta":"What caution do some researchers note?","opciones":["Benefits should not be overstated","Bilingualism always harms","Monolinguals are smarter","Languages are useless"],"correcta":0}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Exploring the Oceans: The Final Frontier', 'Despite decades of exploration, the ocean remains the least understood environment on our planet. More than eighty per cent of the marine depths have never been mapped in detail, and scientists estimate that the vast majority of ocean species are still unknown. The deep sea, beyond the reach of sunlight, is a vast, cold and high-pressure realm where life has evolved remarkable strategies to survive. Hydrothermal vents, discovered in 1977 near the Galapagos Islands, host entire ecosystems that depend on chemical energy rather than sunlight, challenging previous assumptions about the requirements for life. Scientists believe that similar environments could exist beneath the icy crusts of moons such as Europa or Enceladus, making ocean research a key reference for astrobiology. Exploring the deep ocean is enormously complex and expensive, requiring submarines, remotely operated vehicles, sonar mapping and sophisticated sensors. Yet the potential rewards are considerable: new medicines derived from marine organisms, insights into Earth is climate system, renewable energy from waves and tides, and a better understanding of biodiversity in the face of threats such as overfishing, pollution and warming waters. Pressing challenges, however, cloud the picture. Plastic waste, noise pollution from shipping, acidification caused by dissolved carbon dioxide and the mining of the seabed for rare minerals all put marine ecosystems at risk even before they have been properly studied. International agreements, including the recent High Seas Treaty adopted under the United Nations, aim to protect significant areas of the open ocean. Scientists and activists emphasise that responsible exploration and effective conservation must go hand in hand to safeguard this last great frontier.',
'[{"pregunta":"How much of the ocean depths have been mapped in detail?","opciones":["More than 80 per cent","Less than 20 per cent","Around 50 per cent","All of them"],"correcta":1},{"pregunta":"What do hydrothermal vent ecosystems depend on?","opciones":["Sunlight","Chemical energy","Wind","Moonlight"],"correcta":1},{"pregunta":"Why is ocean research relevant to astrobiology?","opciones":["It discovers alien ships","It helps understand life on icy moons","It studies the sun","It tracks satellites"],"correcta":1},{"pregunta":"What aims to protect open ocean areas?","opciones":["The Paris Agreement","The High Seas Treaty","The Kyoto Protocol","The WTO"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Ethics of Space Exploration', 'As humanity prepares for a new era of space exploration, including missions to the Moon, Mars and beyond, fundamental ethical questions are coming to the fore. Who owns outer space? Can nations or private companies claim resources on celestial bodies? How should we protect extraterrestrial environments that might harbour microbial life? The Outer Space Treaty of 1967, ratified by most nations, declares that space shall be the province of all humankind and forbids the appropriation of the Moon or other bodies by any state. Yet its provisions were written before the emergence of ambitious private actors such as SpaceX, Blue Origin and various asteroid-mining ventures, which argue that existing law does not explicitly prohibit commercial extraction of resources. The 2015 U.S. Space Act and similar legislation in Luxembourg allow private companies to profit from materials mined in space, raising objections from countries that fear a new form of colonialism. Scientific ethics are also at stake. Planetary protection protocols aim to prevent contamination of other worlds by Earth microbes and, conversely, the introduction of alien organisms into our biosphere. Critics note that billions spent on space ventures could address pressing problems on Earth, including poverty, disease and climate change; defenders counter that exploration drives scientific breakthroughs, inspires new generations and may eventually be essential for the long-term survival of our species. As space becomes more crowded, with thousands of satellites, debris and commercial activity, international cooperation and updated governance frameworks will be indispensable. The decisions taken now will shape whether humanity is collective presence beyond Earth reflects our highest aspirations or replicates the conflicts and injustices of our planetary history.',
'[{"pregunta":"What does the 1967 Outer Space Treaty declare?","opciones":["Countries can own the Moon","Space is the province of humankind","Only the US can explore","Space is forbidden"],"correcta":1},{"pregunta":"What do private actors argue about existing law?","opciones":["It forbids all private activity","It does not explicitly prohibit commercial extraction","It is perfect","It only applies to astronauts"],"correcta":1},{"pregunta":"What is the goal of planetary protection protocols?","opciones":["Speed up missions","Prevent contamination between worlds","Sell tickets to Mars","Promote tourism"],"correcta":1},{"pregunta":"What do defenders of space exploration claim?","opciones":["It solves all Earth problems","It drives scientific breakthroughs and inspires generations","It is unnecessary","It is purely commercial"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Fast Fashion and Its Hidden Costs', 'Fast fashion, the business model that brings new styles from catwalks to shops in a matter of weeks at remarkably low prices, has transformed the clothing industry over the past two decades. Brands produce thousands of new items every year, encouraging consumers to buy frequently and discard quickly. While this model has made fashion more accessible and economically dynamic, it has also generated severe environmental and social consequences that are increasingly difficult to ignore. The textile industry is one of the most polluting in the world, responsible for around ten per cent of global carbon emissions, enormous water consumption and widespread chemical contamination of rivers. Cotton production uses vast amounts of pesticides and irrigation, while synthetic fibres such as polyester shed microplastics that accumulate in oceans and food chains. Garment workers, many of them women in low-income countries, often face unsafe conditions, long hours and wages below subsistence levels. The 2013 collapse of the Rana Plaza factory in Bangladesh, which killed more than 1,100 people, drew international attention to the human cost of cheap clothing. In response, some brands have adopted sustainability pledges, recycled materials and transparent supply chains, though critics warn that much of this is superficial marketing, a practice known as greenwashing. Consumer awareness is slowly growing, with more people buying second-hand, repairing garments and questioning compulsive shopping habits. Structural change, however, requires stronger regulation, fairer trade rules and a cultural shift away from disposability towards durability, quality and responsibility. The ultimate question is whether we can enjoy fashion without exploiting the people and the planet that make it possible.',
'[{"pregunta":"What percentage of global carbon emissions comes from textiles?","opciones":["Around 1 per cent","Around 10 per cent","Around 50 per cent","None"],"correcta":1},{"pregunta":"What happened at Rana Plaza in 2013?","opciones":["A factory opened","A factory collapsed killing over 1,100 people","A fashion week was held","A new brand launched"],"correcta":1},{"pregunta":"What is greenwashing?","opciones":["Washing clothes with eco detergent","Superficial sustainability marketing","Recycling rivers","A cleaning company"],"correcta":1},{"pregunta":"What cultural shift does the text call for?","opciones":["Towards disposability","Towards durability and responsibility","Towards more purchases","Towards cheaper clothing"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Digital Divide', 'The digital divide refers to the gap between those who have access to modern information and communication technologies and those who do not, or whose access is limited, unreliable or unaffordable. Although the number of internet users worldwide has surpassed five billion, an estimated 2.6 billion people remain offline, mainly in rural and low-income regions of the Global South. This divide is not simply about hardware; it also encompasses differences in connectivity quality, digital literacy, relevant content in local languages and the ability to participate safely in online activities. The COVID-19 pandemic dramatically exposed the consequences of digital inequality, as schools, workplaces and public services moved online virtually overnight. Students without reliable internet or suitable devices fell behind, workers lost income and vulnerable groups struggled to access health information and welfare benefits. Within wealthy nations, rural communities, elderly individuals and low-income families often experience similar difficulties, a reality sometimes overlooked in narratives of universal connectivity. Closing the digital divide is both a moral and an economic imperative. International organisations, governments and private companies have launched initiatives to expand broadband networks, distribute affordable devices and promote digital skills training. Innovative projects use satellites, mesh networks and community-led solutions to reach remote areas. However, true inclusion requires more than infrastructure. It demands meaningful content, fair data policies, protection against surveillance and genuine participation by users in shaping the digital environments they inhabit. As artificial intelligence, automation and online services continue to expand, bridging the digital divide will become ever more urgent to prevent exclusion from turning into a new and deeper form of social inequality in the twenty-first century.',
'[{"pregunta":"How many people are estimated to remain offline?","opciones":["About 10 million","Around 2.6 billion","Only 500 thousand","Almost none"],"correcta":1},{"pregunta":"What did the COVID-19 pandemic expose?","opciones":["The end of the digital divide","The consequences of digital inequality","Too many devices","The lack of websites"],"correcta":1},{"pregunta":"Within wealthy nations, who often experiences difficulties?","opciones":["Only schoolchildren","Rural, elderly and low-income groups","Only bankers","Nobody"],"correcta":1},{"pregunta":"What does true inclusion demand beyond infrastructure?","opciones":["Only faster routers","Meaningful content and fair data policies","More advertising","Only cheaper phones"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Importance of Biodiversity', 'Biodiversity, the astonishing variety of life forms on Earth, is not merely a matter of aesthetic or scientific interest; it is the foundation of ecosystems that sustain human civilisation. Forests, grasslands, wetlands, coral reefs and soils rely on intricate webs of species interacting in ways that provide essential services such as pollination, water purification, climate regulation, nutrient cycling and food production. The loss of even a single species can have cascading effects, sometimes triggering the collapse of entire ecological communities. Scientists warn that we are currently witnessing the sixth mass extinction in Earth is history, this time driven not by asteroid impacts or volcanic eruptions but by human activity. Habitat destruction, deforestation, pollution, overfishing, invasive species, climate change and the wildlife trade are depleting biodiversity at an alarming rate, estimated at one thousand times the natural baseline. The 2019 Global Assessment of the Intergovernmental Science-Policy Platform on Biodiversity and Ecosystem Services concluded that up to one million plant and animal species are threatened with extinction, many within decades. Losing biodiversity also means losing cultural heritage, traditional knowledge and potential sources of food, medicine and inspiration. Protecting it requires urgent, coordinated action at multiple levels: establishing and properly managing protected areas, reforming destructive subsidies, supporting sustainable agriculture and fisheries, combating wildlife crime and, crucially, addressing the underlying drivers of overconsumption and inequality. International agreements like the Kunming-Montreal Global Biodiversity Framework set ambitious targets, such as protecting thirty per cent of land and sea by 2030. Achieving them will demand unprecedented political will, financial resources and the meaningful involvement of indigenous peoples and local communities, who are often the most effective guardians of biodiversity.',
'[{"pregunta":"What mass extinction is currently occurring according to scientists?","opciones":["The first","The sixth","The twentieth","The second"],"correcta":1},{"pregunta":"What is the estimated rate of biodiversity loss?","opciones":["Natural baseline","One thousand times the baseline","Slower than ever","The same as always"],"correcta":1},{"pregunta":"How many species may be threatened with extinction?","opciones":["A dozen","Up to one million","Exactly 500","None"],"correcta":1},{"pregunta":"Who are described as effective guardians of biodiversity?","opciones":["Multinational corporations","Indigenous peoples and local communities","Tourists","Online influencers"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'The Power of Reading', 'In an age dominated by screens, instant messages and short videos, the act of reading long, complex texts might seem like a quaint habit of the past. Yet reading remains one of the most powerful tools for personal development, critical thinking and emotional growth. Scientific studies have shown that regular reading, especially of literary fiction, enhances empathy by allowing readers to inhabit the minds and experiences of others. Through characters navigating moral dilemmas, cultural differences or emotional turmoil, readers exercise their capacity to understand perspectives very different from their own. This cognitive benefit extends to children and adolescents, whose linguistic, analytical and imaginative skills are enriched by exposure to varied and challenging texts from an early age. Reading also strengthens concentration, an ability increasingly undermined by digital distractions that train the brain for rapid, shallow processing rather than sustained focus. Immersing oneself in a novel or essay requires patience, attention and the willingness to follow a line of argument or narrative for extended periods, qualities that translate into academic success and lifelong learning. Furthermore, literature offers consolation, inspiration and a sense of belonging; readers encounter voices across time and space, discovering that their own joys and struggles are part of a broader human experience. Libraries, though sometimes overlooked, play a democratic role by ensuring that access to books is not limited by income. Promoting reading habits, particularly among young people, is therefore not just a cultural preference but a vital investment in individual well-being, informed citizenship and the health of democratic societies facing the challenges of a rapidly changing world.',
'[{"pregunta":"What does literary fiction enhance according to studies?","opciones":["Physical strength","Empathy","Typing speed","Memory of numbers"],"correcta":1},{"pregunta":"What ability is undermined by digital distractions?","opciones":["Concentration","Humour","Eyesight","Language learning"],"correcta":0},{"pregunta":"What democratic role do libraries play?","opciones":["They sell books","They ensure access is not limited by income","They organise protests","They replace schools"],"correcta":1},{"pregunta":"What is described as a vital investment?","opciones":["Promoting reading habits","Screen time","Fast messaging","Advertising"],"correcta":0}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Gender Equality: Progress and Challenges', 'Over the past century, societies around the world have made remarkable progress towards gender equality, yet profound disparities still persist. Women today enjoy rights and opportunities that would have astonished their great-grandmothers: the vote, access to education, professional careers, legal protection from discrimination and growing representation in politics, science and business. International agreements such as the Convention on the Elimination of All Forms of Discrimination against Women have established frameworks for advancing equal rights. Yet the gap is far from closed. Globally, women earn on average around twenty per cent less than men for comparable work, remain underrepresented in leadership positions and perform most unpaid care work in families. In many regions, girls are still denied secondary education, forced into early marriage or subjected to violence that rarely ends in justice. Intersectional perspectives remind us that women of colour, indigenous women, migrants and those with disabilities often face compounded forms of discrimination. Progress has not been linear either: backlash against feminist movements, attacks on reproductive rights and setbacks in legal protection show that gains can be reversed when political circumstances change. Achieving true equality requires more than legal reform; it demands transforming cultural norms, investing in care infrastructure, ensuring safe public spaces and challenging stereotypes from early childhood. Men play a critical role as allies, challenging traditional masculinity and sharing domestic responsibilities. Education, media representation and corporate policies can all contribute to meaningful change. As societies face new challenges such as the digital economy, climate change and demographic shifts, gender equality remains not only a matter of justice but also a condition for sustainable development and the full flourishing of human potential.',
'[{"pregunta":"What is the approximate gender pay gap mentioned?","opciones":["Around 1 per cent","Around 20 per cent","Over 60 per cent","There is none"],"correcta":1},{"pregunta":"What does intersectionality remind us?","opciones":["All women face identical discrimination","Some groups face compounded discrimination","Discrimination does not exist","Only men face problems"],"correcta":1},{"pregunta":"What does true equality demand beyond legal reform?","opciones":["Only new laws","Transforming cultural norms","Ignoring the issue","More statistics"],"correcta":1},{"pregunta":"What role do men play according to the text?","opciones":["Opponents","Allies and challengers of traditional masculinity","Bystanders","Leaders only"],"correcta":1}]'::jsonb),

('ingles', 'bachillerato', '{2}', 'Food Security in the Twenty-First Century', 'Feeding a global population projected to reach nearly ten billion by 2050 while safeguarding the environment is one of the most formidable challenges of our time. Food security, defined as reliable access to sufficient, safe and nutritious food, is far from being achieved. According to the Food and Agriculture Organization, around 735 million people suffered from chronic hunger in 2022, a figure exacerbated by the COVID-19 pandemic, armed conflicts, economic crises and climate change. Paradoxically, obesity and diet-related diseases are also expanding worldwide, revealing the inefficiencies and inequalities of the global food system. Agricultural production must increase while reducing its enormous environmental footprint: food systems currently account for about a third of greenhouse gas emissions, consume most of the world is freshwater and drive deforestation and biodiversity loss. Solutions are multi-faceted. Sustainable practices such as agroecology, precision farming, crop diversification and reduced meat consumption can lower environmental impacts. Technological innovations, including drought-resistant crops, vertical farming and novel proteins from insects or plant-based sources, offer new possibilities. Reducing food waste, which represents around a third of all food produced, is equally essential. Equally important are political and economic reforms: fair trade rules, investment in small-scale farmers, especially women, and robust social safety nets for vulnerable populations. Local knowledge and traditional crops, often neglected in favour of industrial monocultures, can contribute to resilience against climate shocks. Education and consumer awareness also matter, as our daily food choices have implications far beyond our plates. Ensuring food security for future generations requires transforming the entire system with urgency, creativity and a sense of shared responsibility across borders and generations.',
'[{"pregunta":"How many people suffered from chronic hunger in 2022?","opciones":["About 735 million","Around 50 million","Less than 10 million","Over 3 billion"],"correcta":0},{"pregunta":"What share of food produced is wasted?","opciones":["About 5 per cent","Around one third","Almost none","Over 90 per cent"],"correcta":1},{"pregunta":"What proportion of greenhouse gases comes from food systems?","opciones":["About a third","Around 1 per cent","100 per cent","Zero"],"correcta":0},{"pregunta":"What do political reforms need to include according to the text?","opciones":["Ending small-scale farming","Fair trade and investment in small farmers","Only subsidising monocultures","Banning agriculture"],"correcta":1}]'::jsonb);

