INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('frances', 'bachillerato', '{2}', 'La francophonie dans le monde', 'La francophonie désigne l''ensemble des peuples et des pays qui partagent l''usage de la langue française. Selon l''Organisation internationale de la Francophonie, plus de 320 millions de personnes parlent français à travers les cinq continents, faisant de cette langue la cinquième la plus parlée au monde et la deuxième langue étrangère la plus apprise. Bien que la France soit historiquement le berceau de la langue, la francophonie contemporaine est beaucoup plus vaste et diverse: elle rassemble l''Afrique subsaharienne et du Nord, où se trouvent aujourd''hui la majorité des locuteurs, le Québec, la Belgique, la Suisse romande, le Luxembourg, ainsi que des territoires en Asie et en Océanie. Cette diversité culturelle constitue une richesse considérable, car chaque région apporte ses propres accents, expressions et traditions littéraires. Des écrivains comme Léopold Sédar Senghor, Amin Maalouf, Dany Laferrière ou Maryse Condé ont contribué à renouveler la littérature française avec des voix venues d''autres horizons. La francophonie n''est pas seulement linguistique: elle représente aussi un espace politique et culturel qui défend des valeurs comme la diversité, la solidarité et le dialogue entre les cultures. Néanmoins, l''avenir du français dépend de l''engagement des jeunes générations, de la qualité de l''enseignement et de la capacité de la langue à s''adapter aux défis du numérique et de la mondialisation. Les projections démographiques estiment que d''ici 2050, l''Afrique comptera près de 85% des francophones, ce qui modifiera profondément le visage de la francophonie mondiale et renforcera son importance internationale dans un monde multipolaire.',
'[{"pregunta":"Combien de personnes parlent français dans le monde?","opciones":["Environ 100 millions","Plus de 320 millions","Environ 1 milliard","Moins de 50 millions"],"correcta":1},{"pregunta":"Où se trouvera la majorité des francophones en 2050?","opciones":["En Europe","En Afrique","En Amérique","En Asie"],"correcta":1},{"pregunta":"Qui est Léopold Sédar Senghor?","opciones":["Un homme politique français","Un écrivain qui a renouvelé la littérature francophone","Un explorateur","Un musicien"],"correcta":1},{"pregunta":"Que représente la francophonie au-delà de la langue?","opciones":["Un espace militaire","Un espace politique et culturel","Un marché unique","Une religion"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Victor Hugo: écrivain et homme engagé', 'Victor Hugo, né à Besançon en 1802 et mort à Paris en 1885, est sans doute l''une des figures les plus emblématiques de la littérature française. Poète, romancier, dramaturge et homme politique, il a traversé tout le XIXe siècle en laissant une œuvre immense et variée. Dès l''adolescence, il se révèle comme un écrivain précoce et brillant. Avec la préface de Cromwell en 1827 et surtout la bataille d''Hernani en 1830, il devient le chef de file du romantisme français, révoltant contre les règles rigides du classicisme. Ses romans, comme Notre-Dame de Paris et Les Misérables, explorent les injustices sociales, la misère, la condition des femmes, des enfants et des prisonniers. Les Misérables, publié en 1862, reste aujourd''hui l''un des romans les plus lus au monde, adapté au cinéma, au théâtre et à la comédie musicale. Au-delà de la littérature, Hugo fut un homme profondément engagé. Il défendit l''abolition de la peine de mort, l''éducation gratuite et obligatoire, les droits des pauvres et l''idée d''États-Unis d''Europe, avant-goût de l''intégration européenne. Son opposition au coup d''État de Louis-Napoléon Bonaparte en 1851 l''obligea à s''exiler pendant près de vingt ans, d''abord à Bruxelles, puis à Jersey et à Guernesey. De son exil, il continua à écrire et à lutter contre le Second Empire. Lorsqu''il revint en France en 1870, il fut accueilli en héros. Ses funérailles nationales, en 1885, rassemblèrent plus de deux millions de personnes, témoignant de l''admiration que lui vouait tout un peuple.',
'[{"pregunta":"De quoi Victor Hugo devient-il chef de file en 1830?","opciones":["Du réalisme","Du romantisme français","Du symbolisme","Du surréalisme"],"correcta":1},{"pregunta":"Quelle cause humanitaire défendait-il?","opciones":["La monarchie absolue","L''abolition de la peine de mort","La colonisation","La guerre civile"],"correcta":1},{"pregunta":"Pourquoi a-t-il dû s''exiler?","opciones":["Pour voyager","Parce qu''il s''opposait au coup d''État de 1851","Parce qu''il était malade","Pour écrire tranquillement"],"correcta":1},{"pregunta":"Combien de personnes ont assisté à ses funérailles?","opciones":["Quelques centaines","Plus de deux millions","Environ 10 000","Personne"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Le défi du changement climatique', 'Le changement climatique constitue l''un des défis majeurs du XXIe siècle. Les données scientifiques sont aujourd''hui incontestables: la température moyenne de la planète a déjà augmenté de plus d''un degré depuis l''ère préindustrielle, principalement à cause des émissions de gaz à effet de serre provoquées par l''activité humaine. Les conséquences sont déjà visibles partout dans le monde: vagues de chaleur plus fréquentes, incendies de forêt dévastateurs, sécheresses prolongées, inondations, fonte des glaciers et montée du niveau des mers. Les régions les plus vulnérables, souvent les moins responsables des émissions, subissent déjà les effets les plus dramatiques. L''accord de Paris, signé en 2015 lors de la COP21, a marqué une étape importante en fixant l''objectif de limiter le réchauffement à moins de 2 degrés, et si possible à 1,5 degré. Cependant, les engagements actuels des États restent insuffisants pour atteindre ces objectifs ambitieux. La transition énergétique, la sortie progressive des combustibles fossiles, le développement des énergies renouvelables et la réduction de la consommation sont autant de leviers indispensables. Les citoyens ont également un rôle essentiel à jouer, en modifiant leurs habitudes de transport, d''alimentation et de consommation. Les jeunes générations, conscientes de l''urgence, se mobilisent à travers des mouvements comme celui initié par Greta Thunberg et exigent des mesures concrètes. La lutte contre le changement climatique n''est pas seulement un enjeu environnemental, c''est aussi une question de justice sociale et de solidarité entre les peuples et les générations futures.',
'[{"pregunta":"Quelle augmentation de température a déjà eu lieu?","opciones":["Moins de 0,1 degré","Plus d''un degré","Environ 5 degrés","Aucune"],"correcta":1},{"pregunta":"Quel est l''objectif principal de l''accord de Paris?","opciones":["Augmenter les émissions","Limiter le réchauffement à moins de 2 degrés","Interdire les voitures","Supprimer l''agriculture"],"correcta":1},{"pregunta":"Qui subit le plus les effets du changement climatique?","opciones":["Les pays riches","Les régions les plus vulnérables","Personne","Les scientifiques"],"correcta":1},{"pregunta":"Comment est décrite la lutte contre le changement climatique?","opciones":["Une question purement scientifique","Un enjeu environnemental et de justice sociale","Un problème technique uniquement","Un sujet politique oublié"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'La cuisine française, un patrimoine culturel', 'La gastronomie française a été inscrite au patrimoine culturel immatériel de l''humanité par l''UNESCO en 2010, une reconnaissance qui souligne l''importance de cette tradition culinaire dans l''identité et l''histoire du pays. La cuisine française ne se limite pas à une collection de recettes; elle représente un art de vivre, un rituel social et une expression culturelle profondément ancrée dans la société. Le repas français typique suit une structure précise: entrée, plat principal, fromage, dessert, souvent accompagné de vin, et il est partagé en famille ou entre amis autour d''une table conviviale. Chaque région possède ses spécialités qui reflètent l''histoire locale, le climat et les produits du terroir: la bouillabaisse de Marseille, la choucroute d''Alsace, le cassoulet du Sud-Ouest, les crêpes de Bretagne, la fondue savoyarde ou la ratatouille provençale. Les fromages, dont on compte plus de 1 200 variétés, sont emblématiques de cette diversité. Les grands chefs français, d''Escoffier à Paul Bocuse et Alain Ducasse, ont porté la cuisine française au rang de référence mondiale, en formant des générations de cuisiniers dans leurs écoles prestigieuses. Cependant, la tradition culinaire française doit aujourd''hui s''adapter à de nouveaux défis: la mondialisation des goûts, l''essor de la restauration rapide, les préoccupations environnementales et la nécessité de proposer des alternatives végétales. Les jeunes chefs renouvellent la cuisine en combinant respect du terroir, créativité, produits biologiques et influences étrangères. La gastronomie française reste ainsi vivante, évolutive et continue de fasciner le monde entier par son raffinement et sa diversité.',
'[{"pregunta":"Quand la gastronomie française a-t-elle été inscrite à l''UNESCO?","opciones":["En 1980","En 2010","En 2020","Jamais"],"correcta":1},{"pregunta":"Combien de variétés de fromages compte la France?","opciones":["Environ 50","Plus de 1 200","Environ 300","Exactement 10"],"correcta":1},{"pregunta":"Que représente le repas français au-delà de la nourriture?","opciones":["Un simple acte biologique","Un rituel social et culturel","Un événement sportif","Une obligation religieuse"],"correcta":1},{"pregunta":"Comment les jeunes chefs renouvellent-ils la cuisine?","opciones":["En ignorant la tradition","En combinant terroir, créativité et bio","En imitant les fast-foods","En supprimant les plats"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Marie Curie, une scientifique d''exception', 'Marie Curie, née Maria Skłodowska à Varsovie en 1867, est l''une des figures les plus inspirantes de l''histoire des sciences. Issue d''une famille polonaise modeste, elle dut surmonter de nombreux obstacles pour poursuivre ses études, notamment en tant que femme dans un monde académique encore très masculin. Après avoir travaillé comme gouvernante pour financer ses études, elle s''installa à Paris en 1891 et s''inscrivit à la Sorbonne, où elle obtint brillamment ses diplômes en physique et en mathématiques. C''est là qu''elle rencontra Pierre Curie, qui devint son mari et son partenaire scientifique. Ensemble, ils se lancèrent dans l''étude de la radioactivité, un phénomène alors mal compris. Leurs recherches aboutirent à la découverte de deux nouveaux éléments, le polonium et le radium, révolutionnant la physique et la chimie. En 1903, Marie Curie reçut le prix Nobel de physique, devenant la première femme à obtenir cette distinction. Après la mort tragique de Pierre en 1906, elle poursuivit seule ses travaux et obtint un second prix Nobel, cette fois en chimie, en 1911, devenant ainsi la seule personne à avoir reçu un Nobel dans deux disciplines scientifiques différentes. Pendant la Première Guerre mondiale, elle mit ses connaissances au service des blessés en développant les "petites Curies", des unités mobiles de radiographie qui sauvèrent de nombreuses vies. Sa vie entière fut consacrée à la recherche et à la transmission du savoir. Elle mourut en 1934 d''une leucémie, probablement causée par son exposition prolongée aux radiations. Marie Curie demeure un symbole universel de courage, d''excellence et d''engagement scientifique.',
'[{"pregunta":"Où est née Marie Curie?","opciones":["À Paris","À Varsovie","À Berlin","À Vienne"],"correcta":1},{"pregunta":"Quels éléments a-t-elle découverts?","opciones":["L''or et l''argent","Le polonium et le radium","L''uranium seul","Aucun"],"correcta":1},{"pregunta":"Combien de prix Nobel a-t-elle reçus?","opciones":["Aucun","Deux, en physique et en chimie","Un seul","Cinq"],"correcta":1},{"pregunta":"Qu''a-t-elle fait pendant la Première Guerre mondiale?","opciones":["Elle a abandonné la science","Elle a développé les petites Curies mobiles","Elle s''est réfugiée","Elle a écrit des romans"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Les réseaux sociaux et les jeunes', 'Les réseaux sociaux sont devenus omniprésents dans la vie des adolescents et des jeunes adultes. Selon plusieurs études récentes, les jeunes Français passent en moyenne plus de trois heures par jour sur des plateformes comme TikTok, Instagram, Snapchat ou YouTube. Ces applications offrent de nombreux avantages: elles permettent de rester en contact avec ses amis, de découvrir de nouvelles musiques, de s''exprimer à travers des vidéos ou des photos, et même de s''engager dans des causes sociales. Pour certains jeunes, les réseaux sociaux représentent également un espace d''apprentissage informel, où l''on peut suivre des créateurs éducatifs, apprendre des langues ou se tenir informé de l''actualité. Cependant, ces usages intensifs soulèvent de nombreuses inquiétudes. Les spécialistes de la santé mentale alertent sur les liens entre une consommation excessive et l''augmentation de l''anxiété, de la dépression et des troubles du sommeil chez les adolescents. Les algorithmes, conçus pour maximiser l''attention, poussent parfois les utilisateurs vers des contenus problématiques, comme la glorification des régimes extrêmes ou la comparaison constante avec des images retouchées. Le cyberharcèlement reste également une préoccupation majeure, avec des conséquences parfois tragiques sur la vie des victimes. Face à ces enjeux, les pouvoirs publics, les écoles et les familles cherchent à mieux encadrer l''usage des écrans. En France, des lois ont été adoptées pour protéger la vie privée des mineurs et pour limiter l''accès aux plateformes. L''éducation aux médias et au numérique devient essentielle afin que les jeunes apprennent à utiliser ces outils de manière critique, équilibrée et responsable tout au long de leur vie.',
'[{"pregunta":"Combien de temps les jeunes Français passent-ils en moyenne sur les réseaux?","opciones":["Moins d''une heure","Plus de trois heures par jour","Environ dix heures","Jamais"],"correcta":1},{"pregunta":"Quel est un avantage des réseaux sociaux mentionné?","opciones":["Rester en contact et s''exprimer","Dormir plus","Faire du sport","Éviter l''école"],"correcta":0},{"pregunta":"Quelle inquiétude soulèvent les spécialistes?","opciones":["L''amélioration du sommeil","L''augmentation de l''anxiété et de la dépression","La baisse de la créativité uniquement","Une meilleure santé"],"correcta":1},{"pregunta":"Qu''est-ce qui devient essentiel selon le texte?","opciones":["Supprimer les téléphones","L''éducation aux médias et au numérique","Interdire internet","Ignorer le problème"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'La Révolution française et ses idéaux', 'La Révolution française, qui débuta en 1789, représente l''un des événements les plus déterminants de l''histoire européenne et mondiale. Née dans un contexte de profonde crise sociale, économique et politique, elle mit fin à l''Ancien Régime, renversa la monarchie absolue et proclama des principes qui continuent aujourd''hui d''inspirer les démocraties contemporaines. La Déclaration des droits de l''homme et du citoyen, adoptée en août 1789, affirma pour la première fois de manière universelle que les hommes naissent et demeurent libres et égaux en droits. Elle reconnut la liberté d''expression, la liberté de conscience, le droit de propriété et la souveraineté de la nation. Ces idéaux, résumés par la devise "Liberté, Égalité, Fraternité", devinrent le fondement de la République française. Cependant, la Révolution fut aussi une période de violence, de divisions politiques et de guerres. La Terreur, sous l''influence de Robespierre, fit de nombreuses victimes, y compris parmi les révolutionnaires eux-mêmes. Les années suivantes connurent des alternances de régimes, du Directoire à l''Empire napoléonien, avant que la République ne s''établisse durablement au cours du XIXe siècle. L''influence de la Révolution dépassa largement les frontières françaises: elle inspira des mouvements d''émancipation en Europe, en Amérique latine et ailleurs dans le monde. Aujourd''hui encore, la Révolution française est considérée comme un modèle ambivalent, à la fois source d''émancipation et rappel des dangers de l''extrémisme. Ses principes fondamentaux restent présents dans les constitutions modernes et dans les textes internationaux relatifs aux droits humains, témoignant de leur pertinence universelle à travers les siècles.',
'[{"pregunta":"Quand a débuté la Révolution française?","opciones":["En 1715","En 1789","En 1815","En 1870"],"correcta":1},{"pregunta":"Quelle est la devise républicaine française?","opciones":["Travail, Famille, Patrie","Liberté, Égalité, Fraternité","Ordre et Progrès","Dieu et le Roi"],"correcta":1},{"pregunta":"Qu''a proclamé la Déclaration de 1789?","opciones":["Le droit divin","L''égalité en droits de tous les hommes","La supériorité de la noblesse","La colonisation"],"correcta":1},{"pregunta":"Comment la Révolution est-elle considérée aujourd''hui?","opciones":["Comme un modèle parfait","Comme un modèle ambivalent","Comme un échec total","Comme oubliée"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Le cinéma français, un art majeur', 'Le cinéma français occupe une place singulière dans l''histoire et la culture du septième art. C''est en France, à Paris, que les frères Lumière ont présenté en 1895 la première projection publique payante, marquant officiellement la naissance du cinéma. Depuis cette époque, la France a maintenu une tradition cinématographique forte, soutenue par des politiques publiques originales qui protègent la création artistique face à la domination commerciale hollywoodienne. L''exception culturelle française, concept développé dans les années 1990, garantit la diversité des productions, soutient les jeunes réalisateurs et favorise la distribution des films en salle. Des mouvements esthétiques majeurs sont nés en France, notamment la Nouvelle Vague dans les années 1960, menée par des cinéastes comme François Truffaut, Jean-Luc Godard, Agnès Varda et Claude Chabrol, qui renouvelèrent la manière de filmer en privilégiant la liberté de ton, les tournages en décors naturels et l''exploration des émotions quotidiennes. Le Festival de Cannes, créé en 1946, est aujourd''hui l''un des événements cinématographiques les plus prestigieux au monde, réunissant chaque printemps les plus grands artistes et offrant une vitrine internationale au cinéma d''auteur. La France produit chaque année plus de 200 films, avec une grande variété de genres: comédies populaires, drames sociaux, documentaires, thrillers et films historiques. Des acteurs comme Juliette Binoche, Omar Sy ou Marion Cotillard jouissent d''une reconnaissance internationale. Face aux plateformes de streaming qui transforment la consommation culturelle, le cinéma français continue à défendre l''expérience collective de la salle obscure et la spécificité d''un regard artistique irremplaçable sur le monde contemporain.',
'[{"pregunta":"Qui a présenté la première projection publique en 1895?","opciones":["Méliès","Les frères Lumière","Godard","Truffaut"],"correcta":1},{"pregunta":"Quel mouvement est apparu dans les années 1960?","opciones":["Le surréalisme","La Nouvelle Vague","Le réalisme poétique","Le néoréalisme italien"],"correcta":1},{"pregunta":"Quand a été créé le Festival de Cannes?","opciones":["En 1895","En 1946","En 1980","En 2000"],"correcta":1},{"pregunta":"Que défend le cinéma français face au streaming?","opciones":["L''expérience collective de la salle","L''absence de salles","Les films très courts uniquement","Le cinéma muet"],"correcta":0}]'::jsonb),

('frances', 'bachillerato', '{2}', 'L''importance des langues étrangères', 'Dans un monde de plus en plus globalisé, apprendre des langues étrangères est devenu une compétence essentielle pour les jeunes. L''Union européenne elle-même recommande à ses citoyens de maîtriser au moins deux langues étrangères en plus de leur langue maternelle, afin de favoriser la mobilité, l''emploi et la compréhension mutuelle entre les peuples. Les études montrent que connaître plusieurs langues présente de nombreux avantages. Sur le plan personnel, cela ouvre l''accès à d''autres cultures, littératures, musiques et manières de penser. Sur le plan professionnel, les employeurs valorisent de plus en plus les candidats capables de communiquer dans différentes langues, notamment en anglais, mais aussi en espagnol, en allemand, en chinois ou en arabe. Les compétences linguistiques facilitent les études à l''étranger, les stages internationaux et l''accès à des postes à responsabilité dans des entreprises multinationales ou des organisations internationales. Les recherches en neurosciences révèlent également que l''apprentissage des langues stimule le cerveau, améliore la mémoire, la concentration et la créativité, et pourrait même retarder l''apparition de maladies neurodégénératives chez les personnes âgées. Pourtant, l''apprentissage des langues n''est pas toujours facile: il demande du temps, de la patience, de la régularité et, surtout, une exposition réelle à la langue. Les programmes Erasmus+, les échanges scolaires, les films en version originale, les podcasts, les applications mobiles et les rencontres avec des locuteurs natifs sont autant d''outils qui permettent de progresser. L''essentiel est de ne pas craindre de faire des erreurs, car c''est en pratiquant régulièrement que l''on finit par maîtriser une langue étrangère et par s''enrichir culturellement.',
'[{"pregunta":"Combien de langues l''UE recommande-t-elle d''apprendre en plus de la langue maternelle?","opciones":["Une seule","Au moins deux","Cinq","Aucune"],"correcta":1},{"pregunta":"Quel bénéfice cognitif mentionne le texte?","opciones":["Amélioration de la mémoire et concentration","Perte de créativité","Troubles du sommeil","Aucun bénéfice"],"correcta":0},{"pregunta":"Quel programme européen est cité?","opciones":["Horizon","Erasmus+","Schengen","Europol"],"correcta":1},{"pregunta":"Quelle attitude est essentielle selon l''auteur?","opciones":["Éviter de parler","Ne pas craindre de faire des erreurs","Étudier seul toute la vie","Apprendre en silence"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Le Tour de France: un symbole populaire', 'Le Tour de France, créé en 1903 par le journaliste Henri Desgrange pour promouvoir le journal sportif L''Auto, est bien plus qu''une simple course cycliste: c''est un phénomène culturel et populaire profondément inscrit dans l''identité nationale française. Chaque été, pendant trois semaines, les coureurs parcourent environ 3 500 kilomètres à travers le pays, franchissant plaines, collines et surtout les redoutables cols des Alpes et des Pyrénées. L''épreuve est suivie par des millions de téléspectateurs à travers le monde et constitue l''un des événements sportifs les plus regardés de l''année. Au-delà de la compétition, le Tour de France est une occasion unique de faire découvrir les paysages, les villages et le patrimoine français. Les villes étapes rivalisent pour accueillir les coureurs, organiser des fêtes et mettre en valeur leurs spécialités locales. La caravane publicitaire, avec ses voitures décorées et ses goodies jetés au public, contribue à l''atmosphère festive. Le Tour est également chargé d''histoire: certains épisodes légendaires, comme les exploits d''Eddy Merckx, Bernard Hinault ou Miguel Indurain, restent gravés dans la mémoire collective. Cependant, la course a aussi été marquée par des scandales liés au dopage, qui ont terni son image et provoqué des réformes importantes dans la lutte contre les produits interdits. Aujourd''hui, le Tour de France évolue avec son temps: il accueille un nombre croissant de coureurs internationaux, intègre progressivement des épreuves féminines comme le Tour de France Femmes, et s''adapte aux enjeux environnementaux en adoptant des mesures de durabilité. Il demeure un formidable spectacle sportif et humain, célébré chaque année avec enthousiasme à travers tout le pays.',
'[{"pregunta":"En quelle année a été créé le Tour de France?","opciones":["En 1850","En 1903","En 1945","En 2000"],"correcta":1},{"pregunta":"Combien de kilomètres parcourent les coureurs?","opciones":["Environ 500 km","Environ 3 500 km","Environ 10 000 km","Exactement 100 km"],"correcta":1},{"pregunta":"Quel scandale a terni l''image du Tour?","opciones":["Le dopage","Les retards","Les grèves","Les orages"],"correcta":0},{"pregunta":"Quelle évolution récente est mentionnée?","opciones":["L''arrêt du Tour","Le Tour de France Femmes","Un parcours en Asie","La suppression des montagnes"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'L''art impressionniste', 'L''impressionnisme est l''un des mouvements artistiques les plus importants de l''histoire de la peinture française. Né dans les années 1860 et 1870, il rassemble un groupe de jeunes peintres qui cherchent à rompre avec les conventions académiques de leur époque. Parmi eux figurent Claude Monet, Auguste Renoir, Camille Pissarro, Edgar Degas, Berthe Morisot et Alfred Sisley. Leur objectif est de saisir la lumière, les couleurs et les impressions fugitives du monde qui les entoure, en peignant souvent en plein air plutôt qu''en atelier. Leurs toiles représentent des scènes de la vie quotidienne, des paysages urbains ou campagnards, des bords de Seine, des gares, des cafés et des jardins fleuris. Le nom du mouvement provient d''un tableau de Monet intitulé Impression, soleil levant, présenté en 1874 lors de la première exposition du groupe. Un critique d''art employa ce terme de manière moqueuse, mais il fut finalement adopté par les artistes eux-mêmes. À leurs débuts, les impressionnistes furent violemment critiqués par les institutions et rejetés par le Salon officiel. Leur technique, caractérisée par des touches rapides, des couleurs vives et un refus des contours précis, surprit et scandalisa les contemporains habitués à une peinture plus académique. Pourtant, avec le temps, ils gagnèrent la reconnaissance du public et influencèrent profondément l''évolution de l''art moderne. Aujourd''hui, leurs œuvres sont parmi les plus visitées dans les musées du monde entier, comme le musée d''Orsay à Paris. L''impressionnisme est devenu un symbole universel de liberté artistique, de sensibilité à la nature et d''audace face à la tradition.',
'[{"pregunta":"D''où vient le nom de l''impressionnisme?","opciones":["D''un poème","D''un tableau de Monet","D''une chanson","D''un livre"],"correcta":1},{"pregunta":"Où les impressionnistes peignaient-ils souvent?","opciones":["En atelier uniquement","En plein air","Dans les églises","Dans les grottes"],"correcta":1},{"pregunta":"Comment furent-ils accueillis au début?","opciones":["Avec enthousiasme","Avec critiques et rejet","Avec indifférence","Avec honneurs officiels"],"correcta":1},{"pregunta":"Quel musée parisien abrite leurs œuvres?","opciones":["Le Louvre","Le musée d''Orsay","Le Centre Pompidou","Le Grand Palais"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'La laïcité à la française', 'La laïcité est l''un des principes fondamentaux de la République française, consacré par la loi de 1905 relative à la séparation des Églises et de l''État. Ce principe garantit la liberté de conscience de chaque citoyen, l''égalité de tous devant la loi quelle que soit leur religion et la neutralité de l''État en matière religieuse. La laïcité française est souvent décrite comme plus stricte que celle pratiquée dans d''autres pays occidentaux. Elle implique que la République ne reconnaît, ne salarie ni ne subventionne aucun culte, et que l''espace public, notamment l''école, doit demeurer un lieu neutre où les convictions religieuses de chacun sont respectées sans s''imposer aux autres. L''école publique occupe une place centrale dans la laïcité française. Depuis les lois de Jules Ferry sous la Troisième République, l''enseignement est gratuit, obligatoire et laïque, afin de former des citoyens libres et émancipés des influences religieuses. En 2004, une loi a interdit le port de signes religieux ostensibles dans les établissements scolaires publics, ce qui a suscité de vifs débats tant en France qu''à l''étranger. La laïcité est aujourd''hui un sujet souvent discuté, dans un contexte de diversité culturelle et religieuse croissante. Certains la considèrent comme un principe intangible de l''identité républicaine, garant de la cohésion sociale et de l''égalité. D''autres estiment qu''elle doit s''adapter aux réalités contemporaines pour ne pas exclure certaines communautés. Au-delà des débats, la laïcité demeure une valeur essentielle pour comprendre la société française, sa manière de concevoir l''espace public et le vivre-ensemble dans le respect de la diversité.',
'[{"pregunta":"Quelle loi fonde la laïcité française?","opciones":["La loi de 1789","La loi de 1905","La loi de 1958","La loi de 2000"],"correcta":1},{"pregunta":"Que garantit la laïcité?","opciones":["Le pouvoir d''une religion officielle","La liberté de conscience et l''égalité","L''interdiction de croire","La supériorité d''un culte"],"correcta":1},{"pregunta":"Qu''a interdit la loi de 2004?","opciones":["Les livres religieux","Le port de signes religieux ostensibles à l''école publique","La prière à la maison","Les fêtes religieuses"],"correcta":1},{"pregunta":"Quel espace est au cœur de la laïcité?","opciones":["Le stade","L''école publique","Le marché","Le cinéma"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'La Belle Époque et ses transformations', 'La Belle Époque, qui correspond environ à la période allant de 1871 à 1914, désigne en France une époque de grands changements sociaux, culturels et technologiques. Elle fut marquée par un optimisme général, une paix relative entre les grandes puissances européennes et une croissance économique soutenue qui transforma profondément la vie quotidienne. Pendant cette période, Paris devint une capitale artistique et culturelle rayonnante. La ville accueillit l''Exposition universelle de 1889, pour laquelle fut construite la tour Eiffel, aujourd''hui symbole mondial de la France, et celle de 1900, qui attira des millions de visiteurs. Les progrès techniques furent spectaculaires: l''électricité illumina les rues et les théâtres, l''automobile commença à remplacer les calèches, le métro parisien fut inauguré en 1900 et le cinématographe popularisa un nouveau type de divertissement. La culture connut également un essor considérable: le music-hall, les cabarets de Montmartre, les grands cafés littéraires et les galeries d''art firent de Paris un centre mondial de création. Des artistes comme Toulouse-Lautrec immortalisèrent cette vie nocturne, tandis que la mode, le design et l''Art nouveau influencèrent l''Europe entière. Cependant, la Belle Époque ne fut pas belle pour tout le monde. Derrière l''éclat des boulevards se cachaient des inégalités sociales profondes, des conditions de vie difficiles pour les ouvriers et des tensions politiques qui préparèrent le terrain à la Première Guerre mondiale. Malgré cela, cette période reste associée à une image d''élégance, de fête et de foi dans le progrès qui fascine encore aujourd''hui les historiens, les écrivains et les amateurs de la culture française.',
'[{"pregunta":"Quelle tour fut construite pour l''Exposition de 1889?","opciones":["La tour Montparnasse","La tour Eiffel","La tour Saint-Jacques","La tour de Pise"],"correcta":1},{"pregunta":"Quand fut inauguré le métro parisien?","opciones":["En 1871","En 1900","En 1920","En 1960"],"correcta":1},{"pregunta":"Quel artiste a immortalisé la vie nocturne parisienne?","opciones":["Monet","Toulouse-Lautrec","David","Rodin"],"correcta":1},{"pregunta":"Qu''y avait-il derrière l''éclat de cette époque?","opciones":["Une paix totale","Des inégalités sociales profondes","Aucun problème","L''absence de politique"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Simone de Beauvoir et le féminisme', 'Simone de Beauvoir, née à Paris en 1908 et morte en 1986, est l''une des figures majeures du féminisme mondial et de la philosophie du XXe siècle. Formée à la Sorbonne, où elle fut reçue deuxième à l''agrégation de philosophie en 1929, elle partagea sa vie intellectuelle avec Jean-Paul Sartre, avec qui elle forma un couple emblématique de l''existentialisme français. Beauvoir écrivit des romans, des essais philosophiques, des récits autobiographiques et des articles engagés, abordant des thèmes aussi variés que la liberté, la morale, la vieillesse et la condition des femmes. Son ouvrage le plus célèbre, Le Deuxième Sexe, publié en 1949, est considéré comme un texte fondateur du féminisme contemporain. Dans ce livre, elle analyse avec rigueur la manière dont la société a historiquement construit la figure de la femme comme "l''Autre" par rapport à l''homme, à travers des mythes, des lois, une éducation différenciée et des rôles imposés. La phrase célèbre "On ne naît pas femme, on le devient" résume son argument central: le genre n''est pas seulement une réalité biologique, mais aussi une construction sociale et culturelle. Beauvoir défendit le droit à l''avortement, à la contraception et à l''émancipation économique des femmes. Son engagement dépassa largement le cadre français: elle soutint les mouvements de libération dans le monde entier et participa à des causes pacifistes et anticoloniales. Son influence sur les générations suivantes de féministes est considérable. Aujourd''hui encore, Le Deuxième Sexe est étudié dans les universités et ses idées continuent d''inspirer les débats sur l''égalité des sexes, la diversité et la justice sociale à travers le monde.',
'[{"pregunta":"Quel est l''ouvrage le plus célèbre de Simone de Beauvoir?","opciones":["L''Étranger","Le Deuxième Sexe","Madame Bovary","Les Misérables"],"correcta":1},{"pregunta":"Quelle phrase célèbre résume sa pensée?","opciones":["Je pense donc je suis","On ne naît pas femme, on le devient","Liberté, Égalité, Fraternité","Tout est pour le mieux"],"correcta":1},{"pregunta":"Avec quel philosophe partageait-elle sa vie?","opciones":["Camus","Sartre","Foucault","Derrida"],"correcta":1},{"pregunta":"Que défendait-elle pour les femmes?","opciones":["Le droit de vote uniquement","Le droit à l''avortement et l''émancipation économique","Le silence","Le retour au foyer"],"correcta":1}]'::jsonb),

('frances', 'bachillerato', '{2}', 'Les droits des animaux en débat', 'La question des droits des animaux occupe une place croissante dans les débats éthiques contemporains. Alors que pendant longtemps les animaux étaient considérés comme de simples objets ou outils au service de l''homme, de nombreuses voix s''élèvent aujourd''hui pour défendre leur statut d''êtres sensibles méritant protection et respect. En France, le Code civil reconnaît depuis 2015 les animaux comme des "êtres vivants doués de sensibilité", un changement symbolique important même si, dans les faits, ils restent soumis au régime juridique des biens. Plusieurs questions suscitent des débats passionnés. L''élevage intensif, qui entasse des milliers d''animaux dans des conditions souvent dénoncées par les associations de défense, soulève des préoccupations éthiques et environnementales. Les expérimentations scientifiques sur les animaux, même si elles contribuent à des avancées médicales, posent la question des alternatives possibles. La corrida, la chasse, les cirques avec animaux sauvages et certaines pratiques traditionnelles font également l''objet de remises en question. Des philosophes comme Peter Singer, auteur de La Libération animale, ont contribué à populariser l''idée que les animaux ont des intérêts moraux qui méritent d''être pris en compte. Les mouvements véganes, qui refusent toute consommation ou exploitation animale, gagnent en visibilité, notamment chez les jeunes. Face à ces évolutions, des lois sont progressivement adoptées pour améliorer le bien-être animal: interdiction de certaines pratiques cruelles, encadrement plus strict des élevages, fermeture progressive des delphinariums. Néanmoins, les positions restent très diverses et reflètent des valeurs culturelles, économiques et philosophiques variées. Le débat sur les droits des animaux touche finalement à notre propre conception de ce que signifie vivre humainement dans un monde partagé avec d''autres espèces sensibles.',
'[{"pregunta":"Que reconnaît le Code civil français depuis 2015?","opciones":["Les animaux comme des objets","Les animaux comme êtres sensibles","L''interdiction totale d''élevage","La domestication obligatoire"],"correcta":1},{"pregunta":"Quel philosophe est cité?","opciones":["Sartre","Peter Singer","Descartes","Kant"],"correcta":1},{"pregunta":"Quelle pratique est remise en question?","opciones":["La cuisine végétarienne","L''élevage intensif","La marche à pied","La lecture"],"correcta":1},{"pregunta":"Qu''est-ce que le véganisme refuse?","opciones":["Toute consommation ou exploitation animale","L''éducation","Le sport","La musique"],"correcta":0}]'::jsonb);

