INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('valenciano', 'bachillerato', '{2}', 'Joan Fuster i la consciència col·lectiva', 'Joan Fuster (Sueca, 1922 - 1992) és considerat una de les figures més influents del pensament valencià contemporani. Llicenciat en Dret, va dedicar la seua vida a l''assaig, a la crítica literària, al periodisme i a la reflexió sobre la identitat del País Valencià. L''any 1962 va publicar Nosaltres, els valencians, una obra que va marcar profundament la consciència col·lectiva d''una generació i que continua sent un referent imprescindible per a entendre la realitat cultural i política del territori. En aquest llibre, Fuster analitza amb lucidesa la història, la llengua i els reptes socials dels valencians, i reivindica la pertinença del País Valencià als Països Catalans, fonamentada en la comunitat lingüística i cultural compartida amb Catalunya, les Illes Balears i altres territoris de parla catalana. La publicació de l''obra va ser un esdeveniment intel·lectual de primera magnitud, però també va generar polèmiques i reaccions adverses per part de sectors que no compartien la seua visió. Fuster és conegut per la seua ironia fina, el seu estil directe i la seua capacitat de combinar l''erudició amb l''amenitat. Els seus aforismes, recollits en volums com Judicis finals o Consells, proverbis i insolències, revelen un pensador crític, laic i compromés amb les idees il·lustrades. Al llarg de la seua vida va rebre amenaces i fins i tot va patir atemptats per la seua defensa pública de la llengua i de la identitat dels valencians. El llegat de Fuster continua ben viu en l''obra dels seus lectors, i les seues idees són estudiades en les universitats. La seua figura és fonamental per a qualsevol reflexió sobre el present i el futur de la cultura valenciana.',
'[{"pregunta":"Quina obra de Fuster va marcar la consciència col·lectiva?","opciones":["Tirant lo Blanc","Nosaltres, els valencians","La Plaça del Diamant","Canigó"],"correcta":1},{"pregunta":"En quin any es va publicar aquest llibre?","opciones":["1942","1962","1982","2002"],"correcta":1},{"pregunta":"Com es descriu l''estil de Fuster?","opciones":["Solemne i obscur","Irònic, directe i erudit","Senzill i elemental","Romàntic i sentimental"],"correcta":1},{"pregunta":"Què va patir Fuster per les seues idees?","opciones":["Premis oficials","Amenaces i atemptats","Indiferència total","Oblit immediat"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'El Tirant lo Blanc, obra mestra del segle XV', 'Tirant lo Blanc és una novel·la cavalleresca escrita per Joanot Martorell entre 1460 i 1464, i acabada per Martí Joan de Galba. Publicada per primera vegada a València l''any 1490, està considerada una de les grans obres de la literatura universal i una de les fites més importants de la literatura en català. El mateix Miguel de Cervantes, en el famós capítol VI del Quixot, la va qualificar com "el millor llibre del món" per la seua riquesa narrativa, el seu humor i la seua barreja sorprenent de realisme i fantasia. A diferència d''altres llibres de cavalleria de l''època, farcits de fets impossibles i personatges idealitzats, Tirant lo Blanc presenta un protagonista més proper, més humà, capaç de riure, patir, estimar i dubtar. El cavaller Tirant viatja per Anglaterra, Sicília, Rodes, l''Imperi bizantí i el Nord d''Àfrica, on realitza nombroses gestes militars i diplomàtiques i viu una apassionada història d''amor amb la princesa Carmesina. La novel·la combina elements èpics, eròtics, cortesans i humorístics, i retrata amb detall la vida quotidiana de la baixa edat mitjana. Martorell, cavaller valencià format en una època de transició entre el món medieval i els inicis del Renaixement, va saber plasmar amb gran agudesa les tensions socials i polítiques del seu temps. L''obra ha estat traduïda a moltes llengües i ha inspirat generacions de lectors, crítics i creadors. Al País Valencià, Tirant lo Blanc és un referent cultural i identitari que s''estudia en tots els nivells educatius i forma part del patrimoni literari europeu més valuós.',
'[{"pregunta":"Qui va començar a escriure Tirant lo Blanc?","opciones":["Miguel de Cervantes","Joanot Martorell","Ausiàs March","Ramon Llull"],"correcta":1},{"pregunta":"On es va publicar per primera vegada?","opciones":["A Barcelona","A València","A Mallorca","A Madrid"],"correcta":1},{"pregunta":"Com la va qualificar Cervantes?","opciones":["Un llibre medíocre","El millor llibre del món","Un text oblidat","Un assaig filosòfic"],"correcta":1},{"pregunta":"Què diferencia Tirant d''altres novel·les cavalleresques?","opciones":["L''absència d''acció","Un protagonista més humà i proper","La presència de dracs únicament","La seua brevetat"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Ausiàs March, poeta del segle XV', 'Ausiàs March, nascut a Gandia al voltant de 1400 i mort a València l''any 1459, és considerat el primer gran poeta en llengua catalana modern i un dels millors poetes europeus del seu segle. Format en la tradició de la lírica cortesana provençal, va saber alliberar-se dels tòpics de l''amor cortés per a expressar una experiència personal més profunda, més torturada i més original. March va ser el primer poeta que va escriure exclusivament en català, sense recórrer al provençal, cosa que va marcar una fita decisiva en la consolidació literària de la llengua. La seua obra, formada per més de cent vint poemes, aborda temes com l''amor, la mort, el pecat, la consciència moral i la cerca de Déu. Els seus versos revelen un home dividit entre els impulsos del cos i les aspiracions de l''ànima, entre la passió terrenal i la recerca de la salvació espiritual. Aquesta tensió interior dóna a la seua poesia una força dramàtica sorprenent. Un dels seus poemes més coneguts, "Veles e vents han mos desigs complir", és una impressionant metàfora marinera sobre l''amor i la travessia vital. March va utilitzar un llenguatge complex, ric en imatges i reflexions filosòfiques, que exigeix una lectura atenta però recompensa amb una experiència estètica intensa. La seua influència es va estendre per tot l''àmbit lingüístic, i poetes posteriors com Francisco de Quevedo o Garcilaso de la Vega el van reconéixer com un mestre. Avui, la figura d''Ausiàs March és estudiada en les universitats de tot el món i és considerada una de les veus més potents de la literatura europea del segle XV.',
'[{"pregunta":"On va nàixer Ausiàs March?","opciones":["A València","A Gandia","A Barcelona","A Palma"],"correcta":1},{"pregunta":"Què va fer de manera innovadora amb la llengua?","opciones":["Escriure en llatí","Escriure exclusivament en català","Escriure en àrab","No escriure"],"correcta":1},{"pregunta":"Quin tema caracteritza la seua poesia?","opciones":["Humor lleuger","La tensió entre cos i ànima","Cròniques militars","Receptes de cuina"],"correcta":1},{"pregunta":"Com és el seu llenguatge poètic?","opciones":["Elemental","Complex i filosòfic","Infantil","Tècnic i científic"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La Renaixença al País Valencià', 'La Renaixença va ser un moviment cultural, literari i polític que va sorgir a Catalunya i al País Valencià durant el segle XIX amb l''objectiu de recuperar la llengua catalana com a vehicle de cultura i de consciència col·lectiva després de segles de marginació administrativa i educativa. Al País Valencià, aquest moviment va presentar característiques pròpies i va tenir una evolució més complexa i discontínua que a Catalunya. Els seus inicis se situen a mitjan segle XIX, amb figures com Teodor Llorente, Constantí Llombart o Vicent Wenceslau Querol, que van promoure la recuperació literària de la llengua a través de poesies, periòdics i entitats culturals. Llorente va impulsar els Jocs Florals i va fundar la revista Las Provincias, mentre que Llombart va crear l''entitat Lo Rat Penat l''any 1878, amb la intenció d''organitzar activitats per a dignificar la llengua i la cultura valencianes. Tanmateix, la Renaixença valenciana va ser sovint més conservadora i folclòrica que la catalana, més centrada en la celebració nostàlgica del passat que en la construcció d''un projecte polític reivindicatiu. Aquesta dicotomia entre "els arqueològics" i "els sentits" va marcar els debats d''aquell període. Malgrat aquestes limitacions, la Renaixença va posar les bases del valencianisme posterior i va començar un procés lent però constant de recuperació cultural. Noms com el de Vicent Andrés Estellés al segle XX van continuar aquesta tradició des d''una perspectiva més crítica i compromesa. Hui, la Renaixença és considerada un moment clau per a entendre com els valencians han anat reconstruint la seua identitat lingüística i cultural al llarg dels darrers segles.',
'[{"pregunta":"Què era la Renaixença?","opciones":["Un moviment religiós","Un moviment cultural i literari de recuperació lingüística","Una guerra civil","Un règim polític"],"correcta":1},{"pregunta":"Qui va fundar Lo Rat Penat?","opciones":["Teodor Llorente","Constantí Llombart","Joan Fuster","Ausiàs March"],"correcta":1},{"pregunta":"Com es descriu la Renaixença valenciana en comparació amb la catalana?","opciones":["Més política","Més conservadora i folclòrica","Més radical","Més lingüística exclusivament"],"correcta":1},{"pregunta":"Què va posar les bases del valencianisme?","opciones":["El feudalisme","La Renaixença","La Il·lustració espanyola","El romanticisme alemany"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La sociolingüística al País Valencià', 'La sociolingüística estudia les relacions entre la llengua i la societat, i al País Valencià constitueix una disciplina especialment rellevant per a entendre la situació del valencià en la vida pública. La societat valenciana és lingüísticament complexa: conviuen dues llengües oficials, el valencià i el castellà, en un context de diglòssia que s''ha anat modificant al llarg de les últimes dècades. El concepte de diglòssia descriu una situació en la qual dues llengües ocupen funcions socials diferents, generalment amb una llengua considerada "alta" (prestigiosa, utilitzada en contextos formals) i una altra considerada "baixa" (familiar, quotidiana). Durant molts segles, el valencià va ser bandejat dels àmbits oficials, educatius i administratius, fet que va generar un procés conegut com a substitució lingüística: els parlants abandonen progressivament la seua llengua en favor d''una altra més prestigiosa. Aquest procés va ser especialment intens durant la dictadura franquista, quan l''ús públic del valencià era perseguit. A partir de la transició democràtica i de l''Estatut d''Autonomia de 1982, el valencià va recuperar un estatus oficial, es va introduir en l''ensenyament, en els mitjans de comunicació i en les institucions públiques. Tanmateix, la normalització lingüística continua sent un repte. Segons diversos estudis recents, l''ús del valencià en determinats àmbits urbans, entre la gent jove i en les xarxes socials ha davallat. Factors com la mobilitat social, la immigració, el pes dels mitjans en castellà i les incerteses sobre les polítiques lingüístiques expliquen aquesta situació complexa. La sociolingüística ofereix eines per a analitzar aquestes realitats i proposar estratègies de revitalització basades en el prestigi, l''ús social i la transmissió intergeneracional.',
'[{"pregunta":"Què estudia la sociolingüística?","opciones":["Les malalties del llenguatge","Les relacions entre llengua i societat","La fonètica pura","L''etimologia"],"correcta":1},{"pregunta":"Què és la diglòssia?","opciones":["Una malaltia","Una situació on dues llengües ocupen funcions diferents","Un dialecte","Una escriptura"],"correcta":1},{"pregunta":"Quan va recuperar el valencià estatus oficial?","opciones":["Al segle XIX","Amb l''Estatut de 1982","Durant el franquisme","Mai"],"correcta":1},{"pregunta":"Què és la substitució lingüística?","opciones":["Canviar de dialecte","Abandonar la pròpia llengua per una altra més prestigiosa","Aprendre gramàtica","Traduir textos"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Vicent Andrés Estellés, poeta del poble', 'Vicent Andrés Estellés, nascut a Burjassot l''any 1924 i mort a València el 1993, és considerat el poeta més important en llengua catalana del segle XX al País Valencià i una de les figures més destacades de tota la literatura catalana contemporània. Fill d''una família humil, va treballar com a periodista a Las Provincias mentre desenvolupava una obra poètica extensa i profundament compromesa amb la seua terra, la seua llengua i la seua gent. L''obra d''Estellés es caracteritza per combinar la tradició clàssica, especialment les influències d''Ausiàs March, amb un llenguatge popular, directe, carregat de vida quotidiana i d''emocions autèntiques. Els seus poemes parlen de la mort, l''amor, el sexe, la lluita obrera, la repressió política, la infància als carrers de Burjassot i la defensa apassionada de la identitat valenciana. Entre les seues obres més destacades es troben Llibre de meravelles, considerada una de les grans fites de la poesia catalana del segle XX, Mural del País Valencià, Coral romput i L''Hotel París. En el Llibre de meravelles, Estellés aconsegueix retratar amb una sensibilitat extraordinària la vida del poble valencià i la seua resistència silenciosa durant els anys més foscos del franquisme. La seua veu poètica, reconeixible al primer vers, combina ternura i ira, elegància i crueldat, elements cultes i quotidians. Durant molts anys va ser un autor poc reconegut oficialment, però hui és llegit i estudiat arreu del domini lingüístic i és una referència imprescindible per a qualsevol lector de poesia. L''any 2020, per iniciativa del govern valencià, es va declarar Any Estellés, dedicat a difondre la seua figura i obra.',
'[{"pregunta":"On va nàixer Vicent Andrés Estellés?","opciones":["A València","A Burjassot","A Alzira","A Sueca"],"correcta":1},{"pregunta":"Quin poeta clàssic el va influir?","opciones":["Ramon Llull","Ausiàs March","Jordi de Sant Jordi","Joanot Martorell"],"correcta":1},{"pregunta":"Quina obra és considerada una fita de la poesia catalana del XX?","opciones":["Tirant lo Blanc","Llibre de meravelles","Canigó","La plaça del Diamant"],"correcta":1},{"pregunta":"Com es descriu la seua veu poètica?","opciones":["Monòtona i freda","Combinant ternura, ira, cultura i quotidianitat","Purament èpica","Sempre humorística"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Les Falles de València, patrimoni immaterial', 'Les Falles de València són una de les festes més conegudes i espectaculars d''Europa, i van ser declarades Patrimoni Cultural Immaterial de la Humanitat per la UNESCO l''any 2016. Cada any, del 15 al 19 de març, la ciutat de València i moltes poblacions del País Valencià es transformen en un escenari únic de creativitat, art, so i foc. L''origen de les Falles se situa al segle XVIII, quan els fusters de la ciutat cremaven la nit de Sant Josep, patró del gremi, els estris de fusta que ja no necessitaven. Amb el pas dels anys, aquestes fogueres es van anar transformant en monuments d''una complexitat creixent, que avui són veritables obres d''art efímer. Les falles són estructures monumentals, algunes de més de vint metres d''altura, que representen escenes satíriques i crítiques sobre l''actualitat política, social i cultural. Els artistes fallers, autèntics creadors, dediquen mesos a la seua elaboració, combinant tradició artesanal i noves tecnologies. Durant la setmana fallera, la ciutat viu un ambient festiu únic: mascletaes explosives a migdia, castells de focs artificials, ofrenes florals a la Mare de Déu dels Desemparats, processons i festejos als carrers. La nit del 19 de març, anomenada la nit de la cremà, totes les falles són incendiades en un acte ritual que simbolitza la purificació i la renovació. Només en queda una figura, anomenada ninot indultat, salvada per votació popular. Les Falles són molt més que una festa: són un element central de la identitat valenciana, una expressió col·lectiva d''art, humor i compromís amb la pròpia història.',
'[{"pregunta":"En quin any van ser declarades Patrimoni de la Humanitat?","opciones":["1996","2016","2020","1980"],"correcta":1},{"pregunta":"Quin és l''origen de les Falles?","opciones":["Una guerra medieval","Els fusters cremaven estris la nit de Sant Josep","Un decret reial","Una cerimònia religiosa àrab"],"correcta":1},{"pregunta":"Què és una mascletà?","opciones":["Un plat típic","Un acte pirotècnic","Una dansa","Un vestit faller"],"correcta":1},{"pregunta":"Què simbolitza la cremà?","opciones":["El final d''una època política","La purificació i renovació","La venjança","El triomf militar"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Mercè Rodoreda i la literatura femenina', 'Mercè Rodoreda, tot i ser barcelonina, és una de les autores en llengua catalana més llegides i estudiades al País Valencià i a tot el domini lingüístic. Nascuda a Barcelona l''any 1908, va viure l''exili després de la Guerra Civil espanyola, primer a França i després a Suïssa, abans de poder tornar a Catalunya. Aquesta experiència de desarrelament marca profundament la seua obra. La seua novel·la més coneguda, La plaça del Diamant (1962), està considerada una de les grans obres de la literatura europea del segle XX. Narra la història de Natàlia, una dona senzilla que viu els anys de la República, de la Guerra Civil i de la dura postguerra, i mostra amb una sensibilitat extraordinària com els grans esdeveniments històrics afecten les vides corrents, especialment la de les dones. Rodoreda utilitza un llenguatge aparentment senzill, però carregat de símbols, ritme i emoció, capaç de commoure lectors de totes les cultures. La novel·la ha estat traduïda a més de trenta llengües i adaptada al cinema, al teatre i fins i tot a l''òpera. Altres obres seues, com Mirall trencat, Aloma o La mort i la primavera, confirmen la seua qualitat excepcional i la seua capacitat per a explorar la psicologia femenina, la memòria, el pas del temps i els traumes col·lectius. Rodoreda va saber donar veu a les experiències de moltes dones que la història oficial havia ignorat, i per això és avui un referent imprescindible de la literatura feta per dones en llengua catalana. La seua obra es continua reeditant, llegint i estudiant, i continua trobant nous lectors en cada generació.',
'[{"pregunta":"Quina és la novel·la més coneguda de Rodoreda?","opciones":["Tirant lo Blanc","La plaça del Diamant","Canigó","Bearn"],"correcta":1},{"pregunta":"Quan va ser publicada aquesta novel·la?","opciones":["1930","1962","1980","2000"],"correcta":1},{"pregunta":"Qui és la protagonista?","opciones":["Una reina","Natàlia, una dona senzilla","Una soldat","Una artista famosa"],"correcta":1},{"pregunta":"Què explora l''obra de Rodoreda?","opciones":["La ciència ficció","La psicologia femenina i els traumes col·lectius","La vida dels reis","L''art religiós"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Els dialectes del valencià', 'La llengua catalana presenta una rica diversitat dialectal que es manifesta al llarg de tot el seu territori lingüístic. Al País Valencià, el valencià constitueix la variant occidental del català i presenta característiques fonètiques, morfològiques i lèxiques pròpies que l''identifiquen com una modalitat amb personalitat reconeguda. Dins del valencià mateix es distingeixen tradicionalment diversos subdialectes. El valencià castellonenc, parlat a la major part de la província de Castelló, presenta trets que el fan proper al nord-occidental català. El valencià central o apitxat, propi de la ciutat de València i de l''àrea metropolitana, es caracteritza per un seguit de canvis fonètics, com l''ensordiment d''algunes consonants, que li han valgut la fama d''una de les modalitats més peculiars. El valencià meridional o alacantí és parlat al sud, i presenta influència del castellà a causa del contacte prolongat amb aquesta llengua. Aquestes diferències dialectals són una riquesa lingüística i no impedeixen en absolut la comunicació entre parlants de diverses zones. La normativa lingüística, elaborada per l''Acadèmia Valenciana de la Llengua des de l''any 1998, recull totes aquestes variants i estableix un model de llengua culta que reflecteix la unitat del sistema dins del respecte per la diversitat. Els estudis dialectològics aporten dades valuoses sobre l''evolució històrica de la llengua, els contactes amb altres varietats i les tendències actuals de canvi lingüístic. Conéixer la pròpia varietat dialectal és important per a valorar la riquesa del patrimoni lingüístic i contribuir a la seua conservació en un context de pressions culturals i socials que, sovint, tendeixen a homogeneïtzar i simplificar les parles locals tradicionals.',
'[{"pregunta":"Quin és el valencià parlat a València ciutat?","opciones":["Alacantí","Apitxat","Castellonenc","Occidental"],"correcta":1},{"pregunta":"Quin organisme estableix la normativa lingüística?","opciones":["La RAE","L''Acadèmia Valenciana de la Llengua","Lo Rat Penat","L''Institut Cervantes"],"correcta":1},{"pregunta":"Per què l''alacantí té influències del castellà?","opciones":["Per decret polític","Pel contacte prolongat","Per influència francesa","Per casualitat"],"correcta":1},{"pregunta":"Què diu el text sobre les diferències dialectals?","opciones":["Impedeixen la comunicació","Són una riquesa i no impedeixen entendre''s","Cal suprimir-les","Només existeixen al Nord"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'L''horta valenciana: paisatge i patrimoni', 'L''horta de València és un dels paisatges agrícoles més singulars i valuosos d''Europa, fruit de més de mil anys d''història i d''un sistema de reg d''origen medieval herència de l''època andalusina. Aquesta extensa plana verda que envolta la ciutat de València ha estat durant segles el garant de l''alimentació de la població i un dels símbols més característics de la identitat valenciana. El sistema d''irrigació, que aprofita les aigües del riu Túria, s''organitza a través d''una xarxa de séquies que distribueixen l''aigua amb una precisió sorprenent. Les normes que en regulen l''ús són controlades pel Tribunal de les Aigües de València, una institució mil·lenària reconeguda per la UNESCO com a Patrimoni Cultural Immaterial de la Humanitat l''any 2009. Aquest tribunal es reuneix cada dijous a les dotze del migdia davant de la porta dels Apòstols de la catedral, en un acte oral i gratuït on es resolen disputes entre llauradors. Les alqueries, les barraques i els camps conreats de verdures, fruites, arròs, cebes i tarongers formen un mosaic paisatgístic únic, intensament lligat a la gastronomia, la literatura i les tradicions valencianes. Autors com Vicente Blasco Ibáñez, en novel·les com La barraca, van retratar aquesta vida rural amb gran força narrativa. Malauradament, l''horta viu en els últims decennis una pressió urbanística preocupant: l''expansió de la ciutat, la construcció de carreteres i l''abandó d''algunes explotacions amenacen aquest patrimoni insubstituible. Moviments ciutadans, associacions i el govern valencià treballen per a protegir i revitalitzar l''horta mitjançant lleis de protecció, productes de proximitat i turisme sostenible que valore aquest llegat milenari.',
'[{"pregunta":"D''on és herència el sistema de reg?","opciones":["Dels romans","De l''època andalusina","Dels francs","Dels visigots"],"correcta":1},{"pregunta":"Què és el Tribunal de les Aigües?","opciones":["Un organisme jove","Una institució mil·lenària","Un partit polític","Una empresa privada"],"correcta":1},{"pregunta":"Quan es reuneix el Tribunal?","opciones":["Cada diumenge","Cada dijous a les dotze","Cada any","Mai"],"correcta":1},{"pregunta":"Qui va retratar l''horta en La barraca?","opciones":["Fuster","Blasco Ibáñez","Estellés","Martorell"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Comentari de text: estructura i tècnica', 'El comentari de text és un exercici acadèmic fonamental en l''ensenyament secundari i universitari, especialment en les matèries de llengua i literatura. Consisteix en l''anàlisi rigorosa d''un text concret, amb l''objectiu d''entendre''n el sentit profund, identificar-ne els recursos lingüístics i estilístics i interpretar-lo dins del seu context històric i cultural. Per a realitzar un bon comentari cal seguir un mètode ordenat que permeta abordar tots els aspectes rellevants sense perdre''s en generalitats. En primer lloc, cal localitzar el text: identificar-ne l''autor, l''obra, l''època i el gènere literari al qual pertany. Aquesta contextualització ajuda a situar el fragment dins d''un marc més ampli i a entendre''n les circumstàncies de creació. En segon lloc, cal fer un resum del contingut, exposant amb les pròpies paraules les idees principals i secundàries del fragment. A continuació, es procedeix a l''anàlisi del tema central, identificant els motius i les idees clau que hi apareixen. L''anàlisi formal examina els recursos literaris (metàfores, comparacions, personificacions, hipèrboles), les característiques sintàctiques i lèxiques, l''estructura interna, el registre i el to. Un bon comentari evita limitar-se a enumerar figures retòriques sense justificar-ne la funció en el text. Finalment, la conclusió valora l''aportació del fragment, la seua bellesa estètica, la seua originalitat i la seua rellevància per al lector actual. El comentari exigeix lectura atenta, coneixements literaris i capacitat d''argumentació. És un exercici que, més enllà de l''aspecte avaluatiu, forma lectors crítics, sensibles i preparats per a comprendre la complexitat dels textos literaris i no literaris que trobem en la vida.',
'[{"pregunta":"Què és el primer pas en un comentari?","opciones":["Conclusió","Localització de l''autor i l''obra","Valoració estètica","Anàlisi mètrica"],"correcta":1},{"pregunta":"Què ha d''evitar un bon comentari?","opciones":["Contextualitzar","Enumerar figures sense justificar-ne la funció","Fer resum","Llegir atentament"],"correcta":1},{"pregunta":"Què inclou l''anàlisi formal?","opciones":["Només l''ortografia","Recursos, sintaxi, lèxic, estructura i registre","Només dates","Només el títol"],"correcta":1},{"pregunta":"Quin objectiu últim té el comentari?","opciones":["Obtenir una nota","Formar lectors crítics i sensibles","Copiar el text","Memoritzar-lo"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La llengua als mitjans de comunicació', 'Els mitjans de comunicació tenen un paper fonamental en la vitalitat d''una llengua, ja que contribueixen a normalitzar-ne l''ús públic, a ampliar-ne el prestigi social i a difondre''n un model culte entre la població. En el cas del valencià, la presència en els mitjans ha viscut diversos episodis al llarg de les últimes dècades que reflecteixen l''evolució de la situació sociolingüística del País Valencià. L''any 1989 es va crear la Ràdio Televisió Valenciana, amb el canal Canal 9 i Ràdio 9, amb l''objectiu de garantir una programació en valencià de qualitat i contribuir així a la normalització lingüística. Durant els anys següents, aquests mitjans públics van jugar un paper essencial a l''hora d''oferir continguts en valencià a una àmplia audiència. Tanmateix, l''any 2013, Canal 9 va ser tancat per decisió del govern autonòmic, cosa que va deixar al País Valencià sense televisió pública en la llengua pròpia durant alguns anys, amb conseqüències negatives per a la presència pública del valencià. L''any 2018 es va inaugurar À Punt, la nova corporació de mitjans de la Generalitat Valenciana, que va recuperar l''oferta audiovisual en valencià amb una programació renovada i compromesa amb la diversitat i la modernitat. A més dels mitjans públics, també existeixen iniciatives privades, mitjans digitals, revistes culturals i plataformes en línia que contribueixen a donar visibilitat a la llengua. Les xarxes socials ofereixen noves oportunitats per a reforçar l''ús del valencià entre els joves. Tot i això, encara queda camí per recórrer per a aconseguir una presència equilibrada del valencià en els mitjans de comunicació, que reflectisca adequadament la riquesa cultural i lingüística de la societat valenciana contemporània.',
'[{"pregunta":"Quin any es va crear la Ràdio Televisió Valenciana?","opciones":["1975","1989","2000","2018"],"correcta":1},{"pregunta":"Què va passar amb Canal 9 l''any 2013?","opciones":["Va ampliar emissions","Va ser tancat","Va canviar de nom","Va tornar a començar"],"correcta":1},{"pregunta":"Quina és la nova corporació creada el 2018?","opciones":["TV3","À Punt","La 1","Canal Sur"],"correcta":1},{"pregunta":"Quin paper tenen els mitjans per a una llengua?","opciones":["Cap","Normalitzar-ne l''ús i ampliar el prestigi","Limitar-la","Ocultar-la"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'El modernisme literari valencià', 'El modernisme va ser un ampli moviment artístic, literari i cultural que es va desenvolupar a Europa a finals del segle XIX i començaments del XX. Al domini lingüístic català, i de manera particular al País Valencià, va trobar una expressió tardana i sovint minoritària en comparació amb Catalunya, on va florir de manera més intensa i diversa. Els modernistes volien renovar les formes literàries heretades del romanticisme i del realisme, obrint la porta a noves influències europees com el simbolisme francés, el prerafaelitisme anglés o el decadentisme. Al País Valencià, aquesta modernització es va manifestar de maneres diferents segons els autors. Alguns escriptors van continuar una poètica més propera a la tradició del segle XIX, mentre que uns altres van intentar connectar amb els corrents innovadors europeus. Figures com Eduard López-Chavarri, compositor i escriptor, o Maximilià Thous, reconegut per la seua faceta literària i periodística, van contribuir a enriquir el panorama cultural del seu temps. La producció literària modernista valenciana es va caracteritzar per l''atenció a la subjectivitat, al refinament estètic, al simbolisme i al gust per l''art en totes les seues manifestacions. Tanmateix, diverses circumstàncies històriques i socials, com la situació minoritzada del valencià en els àmbits cults, van limitar el desplegament d''aquest moviment. Posteriorment, amb l''arribada del noucentisme i de les avantguardes, la literatura valenciana va experimentar nous canvis. Conèixer el modernisme literari valencià permet entendre els intents de renovació i l''obertura cultural dels primers anys del segle XX, així com les tensions entre tradició i modernitat, entre localisme i cosmopolitisme, que han marcat l''evolució cultural del País Valencià fins avui.',
'[{"pregunta":"Quan es va desenvolupar el modernisme?","opciones":["Al segle XVI","A finals del XIX i començaments del XX","Al segle XVIII","Als anys 2000"],"correcta":1},{"pregunta":"Com va ser el modernisme valencià en comparació al català?","opciones":["Més ampli i profund","Més tardà i minoritari","Idèntic","Inexistent"],"correcta":1},{"pregunta":"Quin corrent europeu va influir en els modernistes?","opciones":["El cubisme","El simbolisme francés","El Renaixement italià","L''impressionisme alemany"],"correcta":1},{"pregunta":"Què caracteritza la producció modernista?","opciones":["L''atenció al refinament estètic i la subjectivitat","El realisme dur","L''èpica medieval","La ciència ficció"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La literatura infantil i juvenil en valencià', 'La literatura infantil i juvenil en llengua catalana, i especialment al País Valencià, ha experimentat un notable desenvolupament durant les últimes dècades. Després d''un llarg període en el qual els llibres per a xiquets i jóvens en valencià eren escassos, la normalització lingüística a partir dels anys vuitanta va impulsar una important producció editorial adreçada als lectors més joves. Aquesta literatura compleix diverses funcions fonamentals: fomenta el gust per la lectura des de les edats primerenques, contribueix a l''aprenentatge i consolidació de la llengua, transmet valors, cultures i tradicions, i ofereix a les noves generacions la possibilitat d''identificar-se amb personatges i històries pròximes a la seua realitat lingüística i cultural. Editorials com Bromera, Tàndem o Edicions del Bullent han publicat al llarg dels anys centenars de títols que abracen des dels àlbums il·lustrats per als més menuts fins a les novel·les juvenils. Autors com Enric Lluch, Vicent Pascual, Carme Miquel, Silvestre Vilaplana o Pasqual Alapont han creat obres reconegudes i llegides amb entusiasme pels lectors valencians. Els temes tractats són molt variats: aventures, amistat, humor, misteri, història, natura, valors socials i problemes actuals com el medi ambient o la diversitat. El premi Enric Valor, convocat per l''editorial Bromera, ha estat durant molts anys un important impuls per a la creació literària juvenil en valencià. Els centres educatius, les biblioteques escolars i les famílies desenvolupen un paper clau a l''hora de facilitar l''accés a aquests llibres i de convertir la lectura en valencià en una experiència plaent i significativa. El futur d''aquesta literatura depèn del suport institucional, de la promoció lectora i del talent dels autors.',
'[{"pregunta":"Quan es va impulsar la literatura infantil en valencià?","opciones":["Als anys 40","A partir dels anys 80","Al segle XIX","Mai"],"correcta":1},{"pregunta":"Quina editorial destacada es menciona?","opciones":["Planeta","Bromera","Anaya","Santillana"],"correcta":1},{"pregunta":"Quin premi impulsa la literatura juvenil en valencià?","opciones":["Premi Cervantes","Premi Enric Valor","Premi Nobel","Premi Goncourt"],"correcta":1},{"pregunta":"Quina és una funció d''aquesta literatura?","opciones":["Substituir la família","Fomentar la lectura i consolidar la llengua","Ignorar la cultura","Reduir el vocabulari"],"correcta":1}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'El teatre contemporani valencià', 'El teatre valencià contemporani, tot i haver viscut moments difícils al llarg del segle XX, ha experimentat un notable renaixement en les últimes dècades i s''ha consolidat com un dels àmbits més dinàmics i creatius de la cultura valenciana actual. Durant el franquisme, l''ús del valencià als escenaris va ser marginat i el teatre en aquesta llengua es va refugiar en grups amateurs i en formes tradicionals com el sainet o els col·loquis populars. A partir de la transició democràtica, i especialment des dels anys vuitanta, es van crear companyies professionals, espais estables i circuits de distribució que van permetre un desenvolupament continuat del teatre en valencià. La Generalitat Valenciana va impulsar el teatre públic amb institucions com el Centre Dramàtic de la Generalitat Valenciana o la Sala Off, i l''Institut Valencià de Cultura gestiona hui el Teatre Rialto i el Teatre Principal de València. A les darreres dècades, autors com Rodolf Sirera, Manuel Molins, Carles Alberola, Paco Zarzoso, Juli Disla i molts altres han enriquit l''escena amb obres originals que combinen qualitat literària i reflexió sobre la societat contemporània. Companyies com Albena Teatre, L''Om Imprebís o Dacsa Produccions han estrenat espectacles reconeguts nacionalment i internacionalment. El teatre valencià aborda temes com la memòria històrica, la identitat, la violència, la política, les relacions humanes i els conflictes socials, amb una estètica variada que va del realisme al teatre experimental. El públic jove, sovint format en els tallers d''escolars i universitaris, continua alimentant un sector que lluita per consolidar-se amb dificultats i il·lusió. Aquest panorama teatral demostra la vitalitat i la capacitat creativa del valencià en l''escena cultural contemporània.',
'[{"pregunta":"Com va sobreviure el teatre valencià durant el franquisme?","opciones":["Va desaparéixer totalment","En grups amateurs i formes tradicionals","Només a la televisió","En llatí"],"correcta":1},{"pregunta":"Quina institució gestiona el Teatre Rialto?","opciones":["Una empresa privada","L''Institut Valencià de Cultura","L''Estat central","La Unió Europea"],"correcta":1},{"pregunta":"Quin autor contemporani és citat?","opciones":["Ausiàs March","Rodolf Sirera","Joanot Martorell","Ramon Llull"],"correcta":1},{"pregunta":"Quins temes tracta el teatre actual?","opciones":["Només mitologia antiga","Memòria, identitat, política, conflictes socials","Només humor lleuger","Només religió"],"correcta":1}]'::jsonb);
